import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TaxCategory {
  FOOD = 'FOOD', // GST only (5%)
  CONTAINERS = 'CONTAINERS' // GST (5%) + PST (7%)
}

export interface Friend {
  id: string;
  name: string;
}

export interface BillItem {
  id: string;
  name: string;
  price: number;
  taxCategory: TaxCategory;
  sharedWith: string[]; // Array of Friend IDs
}

export interface PaymentRecord {
  friendId: string;
  amount: number;
}

export interface Settlement {
  from: string; // Friend ID
  to: string;   // Friend ID
  amount: number;
}

export const GST_RATE = 0.05;
export const PST_RATE = 0.07;

import { GoogleGenAI, Type } from "@google/genai";
import { TaxCategory } from "../types";

export const scanBillWithGemini = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: "Extract items from this restaurant bill. For each item, identify if it is 'FOOD' or 'CONTAINERS' (takeout items). Return names and subtotal prices (before tax). If unsure, assume 'FOOD'."
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            price: { type: Type.NUMBER },
            taxCategory: { 
              type: Type.STRING,
              enum: [TaxCategory.FOOD, TaxCategory.CONTAINERS]
            }
          },
          required: ["name", "price", "taxCategory"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return [];
  }
};

import { BillItem, Friend, TaxCategory, GST_RATE, PST_RATE, Settlement } from '../types';

export const calculateItemTotals = (items: BillItem[]) => {
  let subtotal = 0;
  let gst = 0;
  let pst = 0;

  items.forEach(item => {
    subtotal += item.price;
    gst += item.price * GST_RATE;
    if (item.taxCategory === TaxCategory.CONTAINERS) {
      pst += item.price * PST_RATE;
    }
  });

  return { subtotal, gst, pst, total: subtotal + gst + pst };
};

export const calculateIndividualCosts = (
  friends: Friend[],
  items: BillItem[],
  tipAmount: number
) => {
  const { total: billTotal } = calculateItemTotals(items);
  const costMap: Record<string, number> = {};

  friends.forEach(f => costMap[f.id] = 0);

  items.forEach(item => {
    if (item.sharedWith.length === 0) return;

    const itemGst = item.price * GST_RATE;
    const itemPst = item.taxCategory === TaxCategory.CONTAINERS ? item.price * PST_RATE : 0;
    const itemTotal = item.price + itemGst + itemPst;

    const share = itemTotal / item.sharedWith.length;
    item.sharedWith.forEach(friendId => {
      costMap[friendId] += share;
    });
  });

  // Distribute tip proportionally to the share of the bill
  if (billTotal > 0) {
    friends.forEach(f => {
      const proportion = costMap[f.id] / billTotal;
      costMap[f.id] += proportion * tipAmount;
    });
  }

  return costMap;
};

export const solveDebts = (
  balances: Record<string, number> // Positive means they are owed money, negative means they owe money
): Settlement[] => {
  const settleList: Settlement[] = [];
  const credit = Object.keys(balances)
    .filter(id => balances[id] > 0.01)
    .sort((a, b) => balances[b] - balances[a]);
  const debit = Object.keys(balances)
    .filter(id => balances[id] < -0.01)
    .sort((a, b) => balances[a] - balances[b]);

  let i = 0, j = 0;
  const tempBalances = { ...balances };

  while (i < credit.length && j < debit.length) {
    const creditor = credit[i];
    const debtor = debit[j];
    const amount = Math.min(tempBalances[creditor], -tempBalances[debtor]);

    if (amount > 0.01) {
      settleList.push({
        from: debtor,
        to: creditor,
        amount: Number(amount.toFixed(2))
      });
    }

    tempBalances[creditor] -= amount;
    tempBalances[debtor] += amount;

    if (tempBalances[creditor] < 0.01) i++;
    if (tempBalances[debtor] > -0.01) j++;
  }

  return settleList;
};

import React from 'react';

interface StepProgressProps {
  currentStep: number;
}

const StepProgress: React.FC<StepProgressProps> = ({ currentStep }) => {
  const steps = ["Friends", "Items", "Split", "Payments", "Results"];

  return (
    <div className="flex items-center justify-between mb-8 px-2 overflow-x-auto no-scrollbar">
      {steps.map((label, index) => (
        <React.Fragment key={label}>
          <div className="flex flex-col items-center min-w-[60px]">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-colors ${
              currentStep === index + 1 ? 'bg-orange-500 text-white' : 
              currentStep > index + 1 ? 'bg-green-500 text-white' : 'bg-slate-200 text-slate-500'
            }`}>
              {currentStep > index + 1 ? '✓' : index + 1}
            </div>
            <span className={`text-[10px] uppercase mt-1 font-semibold ${
              currentStep === index + 1 ? 'text-orange-600' : 'text-slate-400'
            }`}>
              {label}
            </span>
          </div>
          {index < steps.length - 1 && (
            <div className="flex-1 h-[2px] bg-slate-200 mx-2 mb-4" />
          )}
        </React.Fragment>
      ))}
    </div>
  );
};

export default StepProgress;

import React, { useState, useCallback, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, PaymentRecord, Settlement } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);

  // Helper to move between steps
  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  // Step 1: Manage Friends
  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  // Step 2: Manage Items
  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id) // Default to shared by all
    };
    setItems([...items, newItem]);
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      setIsScanning(false);
    }
  };

  // Step 3: Split Items
  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const sharedWith = item.sharedWith.includes(friendId)
          ? item.sharedWith.filter(id => id !== friendId)
          : [...item.sharedWith, friendId];
        return { ...item, sharedWith };
      }
      return item;
    }));
  };

  const splitAllEvenly = () => {
    setItems(items.map(item => ({ ...item, sharedWith: friends.map(f => f.id) })));
  };

  // Step 5: Final Settlement
  const calculations = useMemo(() => {
    const itemCosts = calculateIndividualCosts(friends, items, tip);
    const totals = calculateItemTotals(items);
    const grandTotal = totals.total + tip;

    // Balance for each friend: Paid - What they owe
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      const paid = payments[f.id] || 0;
      const owe = itemCosts[f.id] || 0;
      balances[f.id] = paid - owe;
    });

    const settlements = solveDebts(balances);

    return { itemCosts, totals, grandTotal, settlements };
  }, [friends, items, tip, payments]);

  return (
    <div className="min-h-screen pb-24 md:pb-8 flex justify-center">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:my-8 md:rounded-3xl md:shadow-2xl overflow-hidden flex flex-col">

        {/* Header */}
        <header className="bg-orange-500 p-6 text-white text-center">
          <h1 className="text-2xl font-bold">BillSplit BC 🇨🇦</h1>
          <p className="text-orange-100 text-sm">GST/PST Compliant Calculator</p>
        </header>

        <main className="p-6 flex-1">
          <StepProgress currentStep={step} />

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-4">
              <h2 className="text-lg font-semibold text-slate-700">Who's at the table?</h2>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  placeholder="Friend's name"
                  className="flex-1 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-orange-500 outline-none"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      addFriend((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
              </div>
              <div className="grid grid-cols-2 gap-2">
                {friends.map(f => (
                  <div key={f.id} className="bg-slate-50 p-3 rounded-xl flex justify-between items-center group">
                    <span className="font-medium text-slate-700">{f.name}</span>
                    <button onClick={() => removeFriend(f.id)} className="text-red-400 opacity-0 group-hover:opacity-100 transition-opacity">
                      ✕
                    </button>
                  </div>
                ))}
              </div>
              {friends.length === 0 && (
                <div className="text-center py-12 text-slate-400">
                  <p>Add some friends to get started!</p>
                </div>
              )}
            </div>
          )}

          {/* STEP 2: ITEMS */}
          {step === 2 && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-lg font-semibold text-slate-700">What's on the bill?</h2>
                <label className="text-sm text-orange-600 font-bold cursor-pointer hover:underline">
                  {isScanning ? 'Scanning...' : 'Scan Bill (AI)'}
                  <input type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                </label>
              </div>

              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-3">
                <input 
                  id="itemName"
                  type="text" 
                  placeholder="Item name (e.g. Pizza)" 
                  className="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm"
                />
                <div className="flex gap-2">
                  <input 
                    id="itemPrice"
                    type="number" 
                    placeholder="Price ($)" 
                    className="flex-1 border border-slate-200 rounded-lg px-3 py-2 text-sm"
                  />
                  <select id="itemCat" className="bg-white border border-slate-200 rounded-lg px-2 py-2 text-sm">
                    <option value={TaxCategory.FOOD}>Food (GST Only)</option>
                    <option value={TaxCategory.CONTAINERS}>Container (GST+PST)</option>
                  </select>
                </div>
                <button 
                  onClick={() => {
                    const n = document.getElementById('itemName') as HTMLInputElement;
                    const p = document.getElementById('itemPrice') as HTMLInputElement;
                    const c = document.getElementById('itemCat') as HTMLSelectElement;
                    if (n.value && p.value) {
                      addItem(n.value, parseFloat(p.value), c.value as TaxCategory);
                      n.value = ''; p.value = '';
                    }
                  }}
                  className="w-full bg-orange-100 text-orange-600 font-bold py-2 rounded-lg hover:bg-orange-200"
                >
                  Add Item
                </button>
              </div>

              <div className="max-h-60 overflow-y-auto space-y-2 pr-1">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                    <div>
                      <p className="font-semibold text-sm">{item.name}</p>
                      <p className="text-[10px] text-slate-400 uppercase tracking-wider">{item.taxCategory === TaxCategory.FOOD ? 'Food' : 'Takeout'}</p>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="font-mono font-bold">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 text-sm">✕</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-slate-100 space-y-1">
                <div className="flex justify-between text-sm text-slate-500">
                  <span>Subtotal</span>
                  <span>${calculations.totals.subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm text-slate-500">
                  <span>BC Taxes (GST + PST)</span>
                  <span>${(calculations.totals.gst + calculations.totals.pst).toFixed(2)}</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-lg font-semibold text-slate-700">Assign Items</h2>
                <button onClick={splitAllEvenly} className="text-xs font-bold text-orange-500 border border-orange-500 px-2 py-1 rounded">Reset All Even</button>
              </div>

              <div className="space-y-4 max-h-[50vh] overflow-y-auto pr-1">
                {items.map(item => (
                  <div key={item.id} className="border border-slate-100 rounded-2xl overflow-hidden shadow-sm">
                    <div className="bg-slate-50 p-3 flex justify-between items-center border-b border-slate-100">
                      <span className="font-bold text-sm">{item.name}</span>
                      <span className="text-sm font-mono text-slate-600">${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)} w/ tax</span>
                    </div>
                    <div className="p-3 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button
                          key={f.id}
                          onClick={() => toggleShare(item.id, f.id)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all ${
                            item.sharedWith.includes(f.id) 
                              ? 'bg-orange-500 text-white shadow-md' 
                              : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                          }`}
                        >
                          {f.name}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-slate-100">
                <label className="block text-sm font-semibold text-slate-600 mb-1">Total Tip Added ($)</label>
                <input 
                  type="number" 
                  value={tip || ''} 
                  onChange={(e) => setTip(parseFloat(e.target.value) || 0)}
                  className="w-full border border-slate-200 rounded-lg px-4 py-3 text-lg font-bold text-orange-600 outline-none"
                  placeholder="0.00"
                />
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-4">
              <h2 className="text-lg font-semibold text-slate-700">Who paid the bill?</h2>
              <p className="text-sm text-slate-500">Enter the amount each person swiped at the terminal.</p>

              <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 mb-4">
                <div className="flex justify-between items-center text-orange-800">
                  <span className="text-sm font-semibold uppercase tracking-wider">Total to cover</span>
                  <span className="text-xl font-bold">${calculations.grandTotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between items-center mt-1 text-slate-500 text-xs">
                  <span>Current Input Total</span>
                  <span className={Object.values(payments).reduce((a,b)=>a+b,0).toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-green-600 font-bold' : ''}>
                    ${Object.values(payments).reduce((a,b)=>a+b,0).toFixed(2)}
                  </span>
                </div>
              </div>

              <div className="space-y-3">
                {friends.map(f => (
                  <div key={f.id} className="flex items-center gap-4 bg-white p-3 rounded-xl border border-slate-100">
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500">
                      {f.name[0]}
                    </div>
                    <div className="flex-1">
                      <span className="font-semibold text-slate-700">{f.name}</span>
                    </div>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">$</span>
                      <input 
                        type="number" 
                        value={payments[f.id] || ''}
                        onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})}
                        placeholder="0.00"
                        className="w-24 border border-slate-200 rounded-lg pl-6 pr-2 py-2 text-right font-mono"
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-6">
              <div className="text-center">
                <h2 className="text-2xl font-bold text-slate-800">Split Success! 🎉</h2>
                <p className="text-slate-500">Here's how to settle up.</p>
              </div>

              <div className="space-y-4">
                <h3 className="text-xs uppercase font-bold text-slate-400 tracking-widest">Debts to Settle</h3>
                {calculations.settlements.length > 0 ? (
                  <div className="space-y-3">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-slate-50 p-4 rounded-2xl flex items-center gap-4 border border-slate-100">
                          <div className="flex-1">
                            <span className="font-bold text-slate-700">{from}</span>
                            <span className="text-slate-400 mx-2">pays</span>
                            <span className="font-bold text-orange-600">{to}</span>
                          </div>
                          <div className="text-xl font-mono font-black text-slate-800">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-8 bg-green-50 text-green-600 rounded-2xl border border-green-100">
                    <p className="font-bold">Everyone is settled up!</p>
                  </div>
                )}
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-100">
                <h3 className="text-xs uppercase font-bold text-slate-400 tracking-widest">Individual Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center text-sm">
                    <span className="text-slate-600 font-medium">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[10px] text-slate-400">Total Share</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        {/* Sticky Action Footer */}
        <footer className="p-6 bg-slate-50 border-t border-slate-200 flex gap-4 sticky bottom-0">
          {step > 1 && (
            <button 
              onClick={prevStep}
              className="flex-1 bg-slate-200 text-slate-600 font-bold py-4 rounded-2xl hover:bg-slate-300 transition-all"
            >
              Back
            </button>
          )}
          <button 
            onClick={step === 5 ? () => window.location.reload() : nextStep}
            disabled={step === 1 && friends.length < 2}
            className={`flex-[2] py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${
              (step === 1 && friends.length < 2) ? 'bg-slate-300' : 'bg-orange-500 hover:bg-orange-600 active:scale-95'
            }`}
          >
            {step === 5 ? 'New Split' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo } from 'react';
// Added GST_RATE and PST_RATE to imports to fix "Cannot find name" errors
import { Friend, BillItem, TaxCategory, PaymentRecord, Settlement, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);

  // Helper to move between steps
  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  // Step 1: Manage Friends
  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  // Step 2: Manage Items
  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id) // Default to shared by all
    };
    setItems([...items, newItem]);
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      setIsScanning(false);
    }
  };

  // Step 3: Split Items
  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const sharedWith = item.sharedWith.includes(friendId)
          ? item.sharedWith.filter(id => id !== friendId)
          : [...item.sharedWith, friendId];
        return { ...item, sharedWith };
      }
      return item;
    }));
  };

  const splitAllEvenly = () => {
    setItems(items.map(item => ({ ...item, sharedWith: friends.map(f => f.id) })));
  };

  // Step 5: Final Settlement
  const calculations = useMemo(() => {
    const itemCosts = calculateIndividualCosts(friends, items, tip);
    const totals = calculateItemTotals(items);
    const grandTotal = totals.total + tip;

    // Balance for each friend: Paid - What they owe
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      const paid = payments[f.id] || 0;
      const owe = itemCosts[f.id] || 0;
      balances[f.id] = paid - owe;
    });

    const settlements = solveDebts(balances);

    return { itemCosts, totals, grandTotal, settlements };
  }, [friends, items, tip, payments]);

  // Fix: Explicitly typing paidTotal to avoid "unknown" operator errors
  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc: number, curr: number) => acc + (curr || 0), 0),
    [payments]
  );

  return (
    <div className="min-h-screen pb-24 md:pb-8 flex justify-center">
