                    ${paidTotal.toFixed(2)}
                  </span>
                </div>
              </div>

              <div className="space-y-3">
                {friends.map(f => (
                  <div key={f.id} className="flex items-center gap-4 bg-white p-3 rounded-xl border border-slate-100">
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500">
                      {f.name[0]}
                    </div>
                    <div className="flex-1">
                      <span className="font-semibold text-slate-700">{f.name}</span>
                    </div>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">$</span>
                      <input 
                        type="number" 
                        value={payments[f.id] || ''}
                        onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})}
