                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-8 bg-green-50 text-green-600 rounded-2xl border border-green-100">
                    <p className="font-bold">Everyone is settled up!</p>
                  </div>
                )}
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-100">
                <h3 className="text-xs uppercase font-bold text-slate-400 tracking-widest">Individual Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center text-sm">
                    <span className="text-slate-600 font-medium">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[10px] text-slate-400">Total Share</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        {/* Sticky Action Footer */}
        <footer className="p-6 bg-slate-50 border-t border-slate-200 flex gap-4 sticky bottom-0">
          {step > 1 && (
            <button 
              onClick={prevStep}
              className="flex-1 bg-slate-200 text-slate-600 font-bold py-4 rounded-2xl hover:bg-slate-300 transition-all"
            >
              Back
            </button>
          )}
          <button 
            onClick={step === 5 ? () => window.location.reload() : nextStep}
            disabled={step === 1 && friends.length < 2}
            className={`flex-[2] py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${
              (step === 1 && friends.length < 2) ? 'bg-slate-300' : 'bg-orange-500 hover:bg-orange-600 active:scale-95'
            }`}
          >
            {step === 5 ? 'New Split' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

