              <div className="max-h-60 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                    <div>
                      <p className="font-semibold text-sm">{item.name}</p>
                      <p className="text-[10px] text-slate-400 uppercase tracking-wider">{item.taxCategory === TaxCategory.FOOD ? 'Food' : 'Takeout'}</p>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="font-mono font-bold">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 text-sm p-1">✕</button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-slate-100 space-y-1">
                <div className="flex justify-between text-sm text-slate-500">
                  <span>Subtotal</span>
                  <span>${calculations.totals.subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm text-slate-500">
                  <span>BC Taxes (GST + PST)</span>
                  <span>${(calculations.totals.gst + calculations.totals.pst).toFixed(2)}</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-lg font-semibold text-slate-700">Assign Items</h2>
                <button onClick={splitAllEvenly} className="text-xs font-bold text-orange-500 border border-orange-500 px-2 py-1 rounded">Reset All Even</button>
              </div>

              <div className="space-y-4 max-h-[45vh] overflow-y-auto pr-1">
                {items.map(item => (
                  <div key={item.id} className="border border-slate-100 rounded-2xl overflow-hidden shadow-sm">
                    <div className="bg-slate-50 p-3 flex justify-between items-center border-b border-slate-100">
                      <span className="font-bold text-sm truncate max-w-[150px]">{item.name}</span>
                      <span className="text-sm font-mono text-slate-600">${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)}</span>
                    </div>
                    <div className="p-3 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button
                          key={f.id}
                          onClick={() => toggleShare(item.id, f.id)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all ${
                            item.sharedWith.includes(f.id) 
                              ? 'bg-orange-500 text-white shadow-md' 
                              : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                          }`}
                        >
                          {f.name}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-slate-100">
                <div className="flex justify-between items-end mb-2">
                  <label className="text-sm font-semibold text-slate-600">Tip</label>
                  <div className="flex bg-slate-100 rounded-lg p-1 text-[10px] font-bold">
                    <button 
                      onClick={() => setTipMode('percent')}
                      className={`px-3 py-1 rounded-md transition-colors ${tipMode === 'percent' ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                    >
                      %
                    </button>
                    <button 
                      onClick={() => setTipMode('amount')}
                      className={`px-3 py-1 rounded-md transition-colors ${tipMode === 'amount' ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                    >
                      $
                    </button>
                  </div>
                </div>

                {tipMode === 'percent' ? (
                  <div className="flex items-center gap-4">
                    <input 
                      type="number" 
                      value={tipPercent} 
                      onChange={(e) => setTipPercent(parseFloat(e.target.value) || 0)}
                      className="flex-1 border border-slate-200 rounded-lg px-4 py-3 text-lg font-bold text-orange-600 outline-none"
                    />
                    <div className="text-right">
                      <p className="text-xl font-bold text-slate-400">%</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase mt-[-4px] whitespace-nowrap">(${calculations.effectiveTip.toFixed(2)})</p>
                    </div>
                  </div>
                ) : (
                  <div className="relative">
                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">$</span>
                    <input 
                      type="number" 
                      value={tip || ''} 
                      onChange={(e) => setTip(parseFloat(e.target.value) || 0)}
                      className="w-full border border-slate-200 rounded-lg pl-8 pr-4 py-3 text-lg font-bold text-orange-600 outline-none"
                      placeholder="0.00"
                    />
                  </div>
                )}
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-4">
              <h2 className="text-lg font-semibold text-slate-700">Who paid the bill?</h2>

              <div className="bg-orange-50 p-4 rounded-xl border border-orange-100 mb-4">
                <div className="flex justify-between items-center text-orange-800">
                  <span className="text-sm font-semibold uppercase tracking-wider">Total to cover</span>
                  <span className="text-xl font-bold">${calculations.grandTotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between items-center mt-1 text-slate-500 text-xs">
                  <span>Current Input Total</span>
                  <span className={paidTotal.toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-green-600 font-bold' : ''}>
                    ${paidTotal.toFixed(2)}
                  </span>
                </div>
              </div>

              <div className="space-y-3">
                {friends.map(f => (
                  <div key={f.id} className="flex items-center gap-3 bg-white p-3 rounded-xl border border-slate-100 shadow-sm">
                    <div className="w-10 h-10 shrink-0 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500">
                      {f.name[0]}
                    </div>
                    <div className="flex-1 overflow-hidden">
                      <span className="font-semibold text-slate-700 truncate block">{f.name}</span>
                      <button 
                        onClick={() => setSinglePayer(f.id)}
                        className="text-[10px] font-bold text-orange-500 bg-orange-50 px-2 py-0.5 rounded-md hover:bg-orange-100"
                      >
                        Paid Full
                      </button>
                    </div>
                    <div className="relative">
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                      <input 
                        type="number" 
                        value={payments[f.id] || ''}
                        onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})}
                        placeholder="0.00"
                        className="w-24 border border-slate-200 rounded-lg pl-5 pr-2 py-2 text-right font-mono text-sm"
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-6">
              <div className="text-center">
                <h2 className="text-2xl font-bold text-slate-800">Split Success! 🎉</h2>
                <p className="text-slate-500">Here's how to settle up.</p>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xs uppercase font-bold text-slate-400 tracking-widest">Debts to Settle</h3>
                  <button onClick={shareResults} className="text-xs text-orange-500 font-bold flex items-center gap-1">
                    <span>Share Result</span>
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                  </button>
                </div>

                {calculations.settlements.length > 0 ? (
                  <div className="space-y-3">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-slate-50 p-4 rounded-2xl flex items-center gap-4 border border-slate-100">
                          <div className="flex-1">
                            <span className="font-bold text-slate-700">{from}</span>
                            <span className="text-slate-400 mx-2">pays</span>
                            <span className="font-bold text-orange-600">{to}</span>
                          </div>
                          <div className="text-xl font-mono font-black text-slate-800">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-8 bg-green-50 text-green-600 rounded-2xl border border-green-100">
                    <p className="font-bold">Everyone is settled up!</p>
                  </div>
                )}
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-100">
                <h3 className="text-xs uppercase font-bold text-slate-400 tracking-widest">Individual Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center text-sm">
                    <span className="text-slate-600 font-medium">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono font-bold">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[10px] text-slate-400">Their Share</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        <footer className="p-6 bg-slate-50 border-t border-slate-200 flex gap-4 sticky bottom-0">
          {step > 1 && (
            <button 
              onClick={prevStep}
              className="flex-1 bg-white border border-slate-200 text-slate-600 font-bold py-4 rounded-2xl hover:bg-slate-50 transition-all"
            >
              Back
            </button>
          )}
          <button 
            onClick={step === 5 ? () => window.location.reload() : nextStep}
            disabled={step === 1 && friends.length < 2}
            className={`flex-[2] py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${
              (step === 1 && friends.length < 2) ? 'bg-slate-300' : 'bg-orange-500 hover:bg-orange-600 active:scale-95'
            }`}
          >
            {step === 5 ? 'New Split' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, PaymentRecord, Settlement, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [tipMode, setTipMode] = useState<'amount' | 'percent'>('percent');
  const [tipPercent, setTipPercent] = useState<number>(15);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [showQuickEntry, setShowQuickEntry] = useState(false);
  const [quickAmount, setQuickAmount] = useState<string>('');

  // Navigation helpers
  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  // Step 1: Manage Friends
  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  // Step 2: Manage Items
  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id)
    };
    setItems([...items, newItem]);
  };

  const handleQuickTotalAdd = () => {
    const amount = parseFloat(quickAmount);
    if (!isNaN(amount) && amount > 0) {
      addItem("Lump Sum Total", amount, TaxCategory.FOOD);
      setQuickAmount('');
      setShowQuickEntry(false);
    }
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      setIsScanning(false);
    }
  };

  // Calculations
  const calculations = useMemo(() => {
    const totals = calculateItemTotals(items);
    let effectiveTip = tip;
    if (tipMode === 'percent') {
      effectiveTip = totals.subtotal * (tipPercent / 100);
    }

    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip);
    const grandTotal = totals.total + effectiveTip;

    const balances: Record<string, number> = {};
    friends.forEach(f => {
      const paid = payments[f.id] || 0;
      const owe = itemCosts[f.id] || 0;
      balances[f.id] = paid - owe;
    });

    const settlements = solveDebts(balances);
    return { itemCosts, totals, grandTotal, settlements, effectiveTip };
  }, [friends, items, tip, tipMode, tipPercent, payments]);

  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc: number, curr: number) => acc + (curr || 0), 0),
    [payments]
  );

  const setSinglePayer = (friendId: string) => {
    const newPayments: Record<string, number> = {};
    friends.forEach(f => {
      newPayments[f.id] = f.id === friendId ? calculations.grandTotal : 0;
    });
    setPayments(newPayments);
  };

  const shareResults = async () => {
    const text = `🍁 Maple Split Results:\n\n` + 
      `Total Bill: $${calculations.grandTotal.toFixed(2)}\n` +
      `-------------------\n` +
      (calculations.settlements.length > 0 
        ? calculations.settlements.map(s => {
          const from = friends.find(f => f.id === s.from)?.name;
          const to = friends.find(f => f.id === s.to)?.name;
          return `• ${from} pays ${to}: $${s.amount.toFixed(2)}`;
        }).join('\n')
        : "All settled up! No debts. ✅") + 
      `\n\nMade with Maple Split 🍁`;

    if (navigator.share) {
      try {
        await navigator.share({ title: 'Maple Split Bill', text });
      } catch (err) { console.log("Sharing failed", err); }
    } else {
      await navigator.clipboard.writeText(text);
      alert("Results copied to clipboard! Paste it to your chat group.");
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-24 md:pb-8 flex justify-center selection:bg-orange-100">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:my-8 md:rounded-[2.5rem] md:shadow-2xl overflow-hidden flex flex-col border border-slate-100">

        <header className="bg-gradient-to-br from-orange-500 to-red-500 p-8 text-white text-center">
          <h1 className="text-3xl font-extrabold tracking-tight">Maple Split 🍁</h1>
          <p className="text-orange-100 text-sm font-medium mt-1">Canadian Bill Splitting Made Easy</p>
        </header>

        <main className="p-6 flex-1">
          <StepProgress currentStep={step} />

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in duration-300">
              <div className="flex justify-between items-end">
                <h2 className="text-xl font-bold text-slate-800">Who's dining?</h2>
                <span className="text-xs font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded-full uppercase">{friends.length} Friends</span>
              </div>
              <div className="relative group">
                <input 
                  type="text" 
                  placeholder="Enter a name..."
                  className="w-full border-2 border-slate-100 rounded-2xl px-5 py-4 focus:border-orange-500 outline-none transition-all pr-12 text-lg shadow-sm"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      addFriend((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 font-bold text-xl">↵</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                {friends.map(f => (
                  <div key={f.id} className="bg-slate-50 border border-slate-100 p-4 rounded-2xl flex justify-between items-center group hover:bg-white hover:shadow-md transition-all">
                    <span className="font-semibold text-slate-700 truncate">{f.name}</span>
                    <button onClick={() => removeFriend(f.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </div>
                ))}
              </div>
              {friends.length === 0 && (
                <div className="text-center py-16 opacity-40">
                  <div className="text-5xl mb-4">🍽️</div>
                  <p className="text-slate-500 font-medium">Add friends to start splitting!</p>
                </div>
              )}
            </div>
          )}

          {/* STEP 2: ITEMS */}
          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">Add the Bill</h2>
                <label className="flex items-center gap-2 text-sm text-orange-600 font-bold cursor-pointer hover:bg-orange-50 px-3 py-1.5 rounded-full transition-colors border border-orange-100">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                  {isScanning ? 'Scanning...' : 'Scan Bill'}
                  <input type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                </label>
              </div>

              {/* Input Choice Card */}
              <div className="bg-white border-2 border-slate-100 rounded-[2rem] p-5 shadow-sm space-y-4">
                <div className="flex p-1 bg-slate-50 rounded-xl">
                  <button 
                    onClick={() => setShowQuickEntry(false)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${!showQuickEntry ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                  >
                    Itemized Entry
                  </button>
                  <button 
                    onClick={() => setShowQuickEntry(true)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${showQuickEntry ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                  >
                    Quick Lump Sum
                  </button>
                </div>

                {!showQuickEntry ? (
                  <div className="space-y-3">
                    <input 
                      id="itemName"
                      type="text" 
                      placeholder="Item name (e.g. Burger)" 
                      className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm focus:border-orange-400 outline-none"
                    />
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                        <input 
                          id="itemPrice"
                          type="number" 
                          placeholder="0.00" 
                          className="w-full border border-slate-200 rounded-xl pl-6 pr-4 py-3 text-sm focus:border-orange-400 outline-none"
                        />
                      </div>
                      <select id="itemCat" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-3 text-xs font-bold text-slate-600">
                        <option value={TaxCategory.FOOD}>Food (GST)</option>
                        <option value={TaxCategory.CONTAINERS}>Takeout (GST+PST)</option>
                      </select>
                    </div>
                    <button 
                      onClick={() => {
                        const n = document.getElementById('itemName') as HTMLInputElement;
                        const p = document.getElementById('itemPrice') as HTMLInputElement;
                        const c = document.getElementById('itemCat') as HTMLSelectElement;
                        if (n.value && p.value) {
                          addItem(n.value, parseFloat(p.value), c.value as TaxCategory);
                          n.value = ''; p.value = '';
                        }
                      }}
                      className="w-full bg-orange-500 text-white font-bold py-3 rounded-xl hover:bg-orange-600 active:scale-95 transition-all shadow-md shadow-orange-100"
                    >
                      Add Item
                    </button>
                  </div>
                ) : (
                  <div className="space-y-4 animate-in fade-in zoom-in-95 duration-200 py-2">
                    <p className="text-xs text-slate-400 font-medium px-1">This adds one item for the whole bill and splits it evenly.</p>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">$</span>
                      <input 
                        type="number" 
                        value={quickAmount}
                        onChange={(e) => setQuickAmount(e.target.value)}
                        placeholder="Subtotal Amount" 
                        className="w-full border-2 border-orange-100 rounded-2xl pl-10 pr-4 py-4 text-xl font-bold text-orange-600 focus:border-orange-400 outline-none"
                      />
                    </div>
                    <button 
                      onClick={handleQuickTotalAdd}
                      className="w-full bg-slate-900 text-white font-bold py-4 rounded-2xl hover:bg-black active:scale-95 transition-all"
                    >
                      Add Bill Total
                    </button>
                  </div>
                )}
              </div>

              <div className="max-h-[30vh] overflow-y-auto space-y-2 pr-1 custom-scrollbar no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm group">
                    <div>
                      <p className="font-bold text-slate-700">{item.name}</p>
                      <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-full ${item.taxCategory === TaxCategory.FOOD ? 'bg-green-50 text-green-600' : 'bg-blue-50 text-blue-600'}`}>
                        {item.taxCategory === TaxCategory.FOOD ? 'Food (5%)' : 'Takeout (12%)'}
                      </span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="font-mono font-bold text-slate-900">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 p-1">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t-2 border-slate-50 space-y-2">
                <div className="flex justify-between text-sm font-medium text-slate-400">
                  <span>Subtotal</span>
                  <span>${calculations.totals.subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm font-medium text-slate-400">
                  <span>BC Taxes</span>
                  <span>${(calculations.totals.gst + calculations.totals.pst).toFixed(2)}</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">Assign Items</h2>
                <button onClick={splitAllEvenly} className="text-[10px] font-black text-orange-500 border-2 border-orange-500 px-3 py-1 rounded-full uppercase tracking-tighter hover:bg-orange-500 hover:text-white transition-all">Split All Even</button>
              </div>

              <div className="space-y-4 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="bg-white border-2 border-slate-50 rounded-3xl overflow-hidden shadow-sm">
                    <div className="bg-slate-50 px-5 py-3 flex justify-between items-center border-b border-slate-100">
                      <span className="font-bold text-slate-800 truncate">{item.name}</span>
                      <span className="text-xs font-mono font-bold text-slate-500 bg-white px-2 py-1 rounded-lg">
                        ${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)} <span className="text-[8px] opacity-40">W/ TAX</span>
                      </span>
                    </div>
                    <div className="p-4 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button
                          key={f.id}
                          onClick={() => toggleShare(item.id, f.id)}
                          className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border-2 ${
                            item.sharedWith.includes(f.id) 
                              ? 'bg-orange-500 border-orange-500 text-white shadow-lg shadow-orange-100' 
                              : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                          }`}
                        >
                          {f.name}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-6 border-t-2 border-slate-50">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-800">Tipping</label>
                  <div className="flex bg-slate-100 p-1 rounded-xl">
                    <button onClick={() => setTipMode('percent')} className={`px-4 py-1 rounded-lg text-xs font-black ${tipMode === 'percent' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-400'}`}>%</button>
                    <button onClick={() => setTipMode('amount')} className={`px-4 py-1 rounded-lg text-xs font-black ${tipMode === 'amount' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-400'}`}>$</button>
                  </div>
                </div>

                <div className="relative group">
                  <span className={`absolute left-4 top-1/2 -translate-y-1/2 font-bold transition-colors ${tipMode === 'amount' ? 'text-orange-600' : 'hidden'}`}>$</span>
                  <input 
                    type="number" 
                    value={tipMode === 'percent' ? tipPercent : (tip || '')} 
                    onChange={(e) => tipMode === 'percent' ? setTipPercent(parseFloat(e.target.value) || 0) : setTip(parseFloat(e.target.value) || 0)}
                    className={`w-full border-2 border-slate-100 rounded-2xl py-4 text-2xl font-black text-orange-600 focus:border-orange-500 outline-none transition-all ${tipMode === 'amount' ? 'pl-9' : 'px-5'}`}
                  />
                  <span className={`absolute right-4 top-1/2 -translate-y-1/2 font-bold transition-colors ${tipMode === 'percent' ? 'text-orange-600 text-2xl' : 'hidden'}`}>%</span>
                </div>
                {tipMode === 'percent' && <p className="text-[10px] text-right font-bold text-slate-300 mt-1 uppercase">Approx: ${calculations.effectiveTip.toFixed(2)} Tip</p>}
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <h2 className="text-xl font-bold text-slate-800">Who swiped the card?</h2>

              <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 rounded-[2rem] text-white shadow-xl">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Target Amount</p>
                    <span className="text-3xl font-black italic">${calculations.grandTotal.toFixed(2)}</span>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Entered</p>
                    <span className={`text-xl font-bold ${paidTotal.toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-green-400' : 'text-orange-400'}`}>
                      ${paidTotal.toFixed(2)}
                    </span>
                  </div>
                </div>
                <div className="w-full h-1.5 bg-white/10 rounded-full mt-4 overflow-hidden">
                  <div 
                    className="h-full bg-green-400 transition-all duration-500" 
                    style={{ width: `${Math.min((paidTotal / calculations.grandTotal) * 100, 100)}%` }}
                  ></div>
                </div>
              </div>

              <div className="space-y-3">
                {friends.map(f => (
                  <div key={f.id} className="flex items-center gap-3 bg-white p-4 rounded-[1.5rem] border-2 border-slate-50 shadow-sm">
                    <div className="w-12 h-12 shrink-0 rounded-2xl bg-slate-100 flex items-center justify-center font-black text-slate-400 text-xl">
                      {f.name[0]}
                    </div>
                    <div className="flex-1 min-w-0">
                      <span className="font-bold text-slate-800 truncate block text-lg">{f.name}</span>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => setSinglePayer(f.id)}
                        className="bg-orange-50 text-orange-600 font-black text-[10px] px-3 py-1 rounded-xl hover:bg-orange-100 transition-colors uppercase"
                      >
                        ⚡️ Pay All
                      </button>
                      <div className="relative w-28">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">$</span>
                        <input 
                          type="number" 
                          value={payments[f.id] || ''}
                          onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})}
                          placeholder="0.00"
                          className={`w-full border-2 rounded-xl pl-6 pr-3 py-3 text-right font-mono font-bold text-sm outline-none transition-all ${Math.abs((payments[f.id] || 0) - calculations.grandTotal) < 0.01 ? 'border-green-400 bg-green-50/30' : 'border-slate-100'}`}
                        />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-8 animate-in zoom-in-95 duration-500">
              <div className="text-center space-y-2">
                <div className="text-6xl mb-4">🦌</div>
                <h2 className="text-3xl font-black text-slate-800">Settle Up!</h2>
                <p className="text-slate-400 font-medium">Split is finalized. Here's the plan.</p>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xs uppercase font-black text-slate-400 tracking-widest">Debts Summary</h3>
                  <button onClick={shareResults} className="text-xs font-bold text-white bg-orange-500 px-4 py-2 rounded-full flex items-center gap-2 shadow-lg shadow-orange-100 hover:scale-105 active:scale-95 transition-all">
                    <span>Share Details</span>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                  </button>
                </div>

                {calculations.settlements.length > 0 ? (
                  <div className="space-y-4">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-white p-6 rounded-[2rem] flex items-center justify-between border-2 border-slate-50 shadow-sm relative overflow-hidden group">
                          <div className="absolute left-0 top-0 bottom-0 w-2 bg-orange-500 group-hover:w-3 transition-all"></div>
                          <div className="pl-2">
                            <span className="font-extrabold text-slate-900 block text-lg">{from}</span>
                            <div className="flex items-center gap-2 text-slate-400 my-0.5">
                              <span className="text-[10px] font-black uppercase tracking-tighter italic">Transferring to</span>
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                            </div>
                            <span className="font-extrabold text-orange-600 block text-lg">{to}</span>
                          </div>
                          <div className="text-3xl font-black text-slate-900 font-mono">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-green-50 border-2 border-green-100 rounded-[2.5rem]">
                    <div className="text-4xl mb-2">✅</div>
                    <p className="font-black text-green-700 uppercase text-xs tracking-widest">Everyone is Square!</p>
                  </div>
                )}
              </div>

              <div className="space-y-3 pt-8 border-t-2 border-slate-50">
                <h3 className="text-xs uppercase font-black text-slate-300 tracking-widest">Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center bg-slate-50/50 px-4 py-3 rounded-2xl">
                    <span className="text-slate-600 font-bold">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono font-black text-slate-900">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Total Share</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        <footer className="p-8 bg-slate-50/80 backdrop-blur-md border-t border-slate-100 flex gap-4 sticky bottom-0">
          {step > 1 && (
            <button 
              onClick={prevStep}
              className="flex-1 bg-white border-2 border-slate-100 text-slate-500 font-black py-4 rounded-2xl hover:bg-slate-50 transition-all shadow-sm uppercase text-xs tracking-widest"
            >
              Back
            </button>
          )}
          <button 
            onClick={step === 5 ? () => window.location.reload() : nextStep}
            disabled={step === 1 && friends.length < 2}
            className={`flex-[2] py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.2em] text-white shadow-2xl transition-all ${
              (step === 1 && friends.length < 2) 
                ? 'bg-slate-300 shadow-none grayscale opacity-50' 
                : 'bg-slate-900 hover:bg-black active:scale-95 shadow-slate-200'
            }`}
          >
            {step === 5 ? 'New Split 🍁' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, PaymentRecord, Settlement, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [tipMode, setTipMode] = useState<'amount' | 'percent'>('percent');
  const [tipPercent, setTipPercent] = useState<number>(15);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [showQuickEntry, setShowQuickEntry] = useState(false);
  const [quickAmount, setQuickAmount] = useState<string>('');

  // Navigation helpers
  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  // Step 1: Manage Friends
  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  // Step 2: Manage Items
  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id)
    };
    setItems([...items, newItem]);
  };

  const handleQuickTotalAdd = () => {
    const amount = parseFloat(quickAmount);
    if (!isNaN(amount) && amount > 0) {
      addItem("Lump Sum Total", amount, TaxCategory.FOOD);
      setQuickAmount('');
      setShowQuickEntry(false);
    }
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  // Fix: Added toggleShare function to allow selecting/deselecting which friends share an item
  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const isShared = item.sharedWith.includes(friendId);
        return {
          ...item,
          sharedWith: isShared 
            ? item.sharedWith.filter(id => id !== friendId)
            : [...item.sharedWith, friendId]
        };
      }
      return item;
    }));
  };

  // Fix: Added splitAllEvenly function to reset all items to be shared by everyone
  const splitAllEvenly = () => {
    const allFriendIds = friends.map(f => f.id);
    setItems(items.map(item => ({
      ...item,
      sharedWith: [...allFriendIds]
    })));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      setIsScanning(false);
    }
  };

  // Calculations
  const calculations = useMemo(() => {
    const totals = calculateItemTotals(items);
    let effectiveTip = tip;
    if (tipMode === 'percent') {
      effectiveTip = totals.subtotal * (tipPercent / 100);
    }

    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip);
    const grandTotal = totals.total + effectiveTip;

    const balances: Record<string, number> = {};
    friends.forEach(f => {
      const paid = payments[f.id] || 0;
      const owe = itemCosts[f.id] || 0;
      balances[f.id] = paid - owe;
    });

    const settlements = solveDebts(balances);
    return { itemCosts, totals, grandTotal, settlements, effectiveTip };
  }, [friends, items, tip, tipMode, tipPercent, payments]);

  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc: number, curr: number) => acc + (curr || 0), 0),
    [payments]
  );

  const setSinglePayer = (friendId: string) => {
    const newPayments: Record<string, number> = {};
    friends.forEach(f => {
      newPayments[f.id] = f.id === friendId ? calculations.grandTotal : 0;
    });
    setPayments(newPayments);
  };

  const shareResults = async () => {
    const text = `🍁 Maple Split Results:\n\n` + 
      `Total Bill: $${calculations.grandTotal.toFixed(2)}\n` +
      `-------------------\n` +
      (calculations.settlements.length > 0 
        ? calculations.settlements.map(s => {
          const from = friends.find(f => f.id === s.from)?.name;
          const to = friends.find(f => f.id === s.to)?.name;
          return `• ${from} pays ${to}: $${s.amount.toFixed(2)}`;
        }).join('\n')
        : "All settled up! No debts. ✅") + 
      `\n\nMade with Maple Split 🍁`;

    if (navigator.share) {
      try {
        await navigator.share({ title: 'Maple Split Bill', text });
      } catch (err) { console.log("Sharing failed", err); }
    } else {
      await navigator.clipboard.writeText(text);
      alert("Results copied to clipboard! Paste it to your chat group.");
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-24 md:pb-8 flex justify-center selection:bg-orange-100">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:my-8 md:rounded-[2.5rem] md:shadow-2xl overflow-hidden flex flex-col border border-slate-100">

        <header className="bg-gradient-to-br from-orange-500 to-red-500 p-8 text-white text-center">
          <h1 className="text-3xl font-extrabold tracking-tight">Maple Split 🍁</h1>
          <p className="text-orange-100 text-sm font-medium mt-1">Canadian Bill Splitting Made Easy</p>
        </header>

        <main className="p-6 flex-1">
          <StepProgress currentStep={step} />

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in duration-300">
              <div className="flex justify-between items-end">
                <h2 className="text-xl font-bold text-slate-800">Who's dining?</h2>
                <span className="text-xs font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded-full uppercase">{friends.length} Friends</span>
              </div>
              <div className="relative group">
                <input 
                  type="text" 
                  placeholder="Enter a name..."
                  className="w-full border-2 border-slate-100 rounded-2xl px-5 py-4 focus:border-orange-500 outline-none transition-all pr-12 text-lg shadow-sm"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      addFriend((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 font-bold text-xl">↵</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                {friends.map(f => (
                  <div key={f.id} className="bg-slate-50 border border-slate-100 p-4 rounded-2xl flex justify-between items-center group hover:bg-white hover:shadow-md transition-all">
                    <span className="font-semibold text-slate-700 truncate">{f.name}</span>
                    <button onClick={() => removeFriend(f.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </div>
                ))}
              </div>
              {friends.length === 0 && (
                <div className="text-center py-16 opacity-40">
                  <div className="text-5xl mb-4">🍽️</div>
                  <p className="text-slate-500 font-medium">Add friends to start splitting!</p>
                </div>
              )}
            </div>
          )}

          {/* STEP 2: ITEMS */}
          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">Add the Bill</h2>
                <label className="flex items-center gap-2 text-sm text-orange-600 font-bold cursor-pointer hover:bg-orange-50 px-3 py-1.5 rounded-full transition-colors border border-orange-100">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                  {isScanning ? 'Scanning...' : 'Scan Bill'}
                  <input type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                </label>
              </div>

              {/* Input Choice Card */}
              <div className="bg-white border-2 border-slate-100 rounded-[2rem] p-5 shadow-sm space-y-4">
                <div className="flex p-1 bg-slate-50 rounded-xl">
                  <button 
                    onClick={() => setShowQuickEntry(false)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${!showQuickEntry ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                  >
                    Itemized Entry
                  </button>
                  <button 
                    onClick={() => setShowQuickEntry(true)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${showQuickEntry ? 'bg-white shadow-sm text-orange-600' : 'text-slate-400'}`}
                  >
                    Quick Lump Sum
                  </button>
                </div>

                {!showQuickEntry ? (
                  <div className="space-y-3">
                    <input 
                      id="itemName"
                      type="text" 
                      placeholder="Item name (e.g. Burger)" 
                      className="w-full border border-slate-200 rounded-xl px-4 py-3 text-sm focus:border-orange-400 outline-none"
                    />
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">$</span>
                        <input 
                          id="itemPrice"
                          type="number" 
                          placeholder="0.00" 
                          className="w-full border border-slate-200 rounded-xl pl-6 pr-4 py-3 text-sm focus:border-orange-400 outline-none"
                        />
                      </div>
                      <select id="itemCat" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-3 text-xs font-bold text-slate-600">
                        <option value={TaxCategory.FOOD}>Food (GST)</option>
                        <option value={TaxCategory.CONTAINERS}>Takeout (GST+PST)</option>
                      </select>
                    </div>
                    <button 
                      onClick={() => {
                        const n = document.getElementById('itemName') as HTMLInputElement;
                        const p = document.getElementById('itemPrice') as HTMLInputElement;
                        const c = document.getElementById('itemCat') as HTMLSelectElement;
                        if (n.value && p.value) {
                          addItem(n.value, parseFloat(p.value), c.value as TaxCategory);
                          n.value = ''; p.value = '';
                        }
                      }}
                      className="w-full bg-orange-500 text-white font-bold py-3 rounded-xl hover:bg-orange-600 active:scale-95 transition-all shadow-md shadow-orange-100"
                    >
                      Add Item
                    </button>
                  </div>
                ) : (
                  <div className="space-y-4 animate-in fade-in zoom-in-95 duration-200 py-2">
                    <p className="text-xs text-slate-400 font-medium px-1">This adds one item for the whole bill and splits it evenly.</p>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">$</span>
                      <input 
                        type="number" 
                        value={quickAmount}
                        onChange={(e) => setQuickAmount(e.target.value)}
                        placeholder="Subtotal Amount" 
                        className="w-full border-2 border-orange-100 rounded-2xl pl-10 pr-4 py-4 text-xl font-bold text-orange-600 focus:border-orange-400 outline-none"
                      />
                    </div>
                    <button 
                      onClick={handleQuickTotalAdd}
                      className="w-full bg-slate-900 text-white font-bold py-4 rounded-2xl hover:bg-black active:scale-95 transition-all"
                    >
                      Add Bill Total
                    </button>
                  </div>
                )}
              </div>

              <div className="max-h-[30vh] overflow-y-auto space-y-2 pr-1 custom-scrollbar no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm group">
                    <div>
                      <p className="font-bold text-slate-700">{item.name}</p>
                      <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-full ${item.taxCategory === TaxCategory.FOOD ? 'bg-green-50 text-green-600' : 'bg-blue-50 text-blue-600'}`}>
                        {item.taxCategory === TaxCategory.FOOD ? 'Food (5%)' : 'Takeout (12%)'}
                      </span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="font-mono font-bold text-slate-900">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 p-1">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t-2 border-slate-50 space-y-2">
                <div className="flex justify-between text-sm font-medium text-slate-400">
                  <span>Subtotal</span>
                  <span>${calculations.totals.subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-sm font-medium text-slate-400">
                  <span>BC Taxes</span>
                  <span>${(calculations.totals.gst + calculations.totals.pst).toFixed(2)}</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800">Assign Items</h2>
                <button onClick={splitAllEvenly} className="text-[10px] font-black text-orange-500 border-2 border-orange-500 px-3 py-1 rounded-full uppercase tracking-tighter hover:bg-orange-500 hover:text-white transition-all">Split All Even</button>
              </div>

              <div className="space-y-4 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="bg-white border-2 border-slate-50 rounded-3xl overflow-hidden shadow-sm">
                    <div className="bg-slate-50 px-5 py-3 flex justify-between items-center border-b border-slate-100">
                      <span className="font-bold text-slate-800 truncate">{item.name}</span>
                      <span className="text-xs font-mono font-bold text-slate-500 bg-white px-2 py-1 rounded-lg">
                        ${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)} <span className="text-[8px] opacity-40">W/ TAX</span>
                      </span>
                    </div>
                    <div className="p-4 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button
                          key={f.id}
                          onClick={() => toggleShare(item.id, f.id)}
                          className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border-2 ${
                            item.sharedWith.includes(f.id) 
                              ? 'bg-orange-500 border-orange-500 text-white shadow-lg shadow-orange-100' 
                              : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                          }`}
                        >
                          {f.name}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-6 border-t-2 border-slate-50">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-800">Tipping</label>
                  <div className="flex bg-slate-100 p-1 rounded-xl">
                    <button onClick={() => setTipMode('percent')} className={`px-4 py-1 rounded-lg text-xs font-black ${tipMode === 'percent' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-400'}`}>%</button>
                    <button onClick={() => setTipMode('amount')} className={`px-4 py-1 rounded-lg text-xs font-black ${tipMode === 'amount' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-400'}`}>$</button>
                  </div>
                </div>

                <div className="relative group">
                  <span className={`absolute left-4 top-1/2 -translate-y-1/2 font-bold transition-colors ${tipMode === 'amount' ? 'text-orange-600' : 'hidden'}`}>$</span>
                  <input 
                    type="number" 
                    value={tipMode === 'percent' ? tipPercent : (tip || '')} 
                    onChange={(e) => tipMode === 'percent' ? setTipPercent(parseFloat(e.target.value) || 0) : setTip(parseFloat(e.target.value) || 0)}
                    className={`w-full border-2 border-slate-100 rounded-2xl py-4 text-2xl font-black text-orange-600 focus:border-orange-500 outline-none transition-all ${tipMode === 'amount' ? 'pl-9' : 'px-5'}`}
                  />
                  <span className={`absolute right-4 top-1/2 -translate-y-1/2 font-bold transition-colors ${tipMode === 'percent' ? 'text-orange-600 text-2xl' : 'hidden'}`}>%</span>
                </div>
                {tipMode === 'percent' && <p className="text-[10px] text-right font-bold text-slate-300 mt-1 uppercase">Approx: ${calculations.effectiveTip.toFixed(2)} Tip</p>}
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <h2 className="text-xl font-bold text-slate-800">Who swiped the card?</h2>

              <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 rounded-[2rem] text-white shadow-xl">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Target Amount</p>
                    <span className="text-3xl font-black italic">${calculations.grandTotal.toFixed(2)}</span>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Entered</p>
                    <span className={`text-xl font-bold ${paidTotal.toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-green-400' : 'text-orange-400'}`}>
                      ${paidTotal.toFixed(2)}
                    </span>
                  </div>
                </div>
                <div className="w-full h-1.5 bg-white/10 rounded-full mt-4 overflow-hidden">
                  <div 
                    className="h-full bg-green-400 transition-all duration-500" 
                    style={{ width: `${Math.min((paidTotal / calculations.grandTotal) * 100, 100)}%` }}
                  ></div>
                </div>
              </div>

              <div className="space-y-3">
                {friends.map(f => (
                  <div key={f.id} className="flex items-center gap-3 bg-white p-4 rounded-[1.5rem] border-2 border-slate-50 shadow-sm">
                    <div className="w-12 h-12 shrink-0 rounded-2xl bg-slate-100 flex items-center justify-center font-black text-slate-400 text-xl">
                      {f.name[0]}
                    </div>
                    <div className="flex-1 min-w-0">
                      <span className="font-bold text-slate-800 truncate block text-lg">{f.name}</span>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => setSinglePayer(f.id)}
                        className="bg-orange-50 text-orange-600 font-black text-[10px] px-3 py-1 rounded-xl hover:bg-orange-100 transition-colors uppercase"
                      >
                        ⚡️ Pay All
                      </button>
                      <div className="relative w-28">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">$</span>
                        <input 
                          type="number" 
                          value={payments[f.id] || ''}
                          onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})}
                          placeholder="0.00"
                          className={`w-full border-2 rounded-xl pl-6 pr-3 py-3 text-right font-mono font-bold text-sm outline-none transition-all ${Math.abs((payments[f.id] || 0) - calculations.grandTotal) < 0.01 ? 'border-green-400 bg-green-50/30' : 'border-slate-100'}`}
                        />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-8 animate-in zoom-in-95 duration-500">
              <div className="text-center space-y-2">
                <div className="text-6xl mb-4">🦌</div>
                <h2 className="text-3xl font-black text-slate-800">Settle Up!</h2>
                <p className="text-slate-400 font-medium">Split is finalized. Here's the plan.</p>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <h3 className="text-xs uppercase font-black text-slate-400 tracking-widest">Debts Summary</h3>
                  <button onClick={shareResults} className="text-xs font-bold text-white bg-orange-500 px-4 py-2 rounded-full flex items-center gap-2 shadow-lg shadow-orange-100 hover:scale-105 active:scale-95 transition-all">
                    <span>Share Details</span>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                  </button>
                </div>

                {calculations.settlements.length > 0 ? (
                  <div className="space-y-4">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-white p-6 rounded-[2rem] flex items-center justify-between border-2 border-slate-50 shadow-sm relative overflow-hidden group">
                          <div className="absolute left-0 top-0 bottom-0 w-2 bg-orange-500 group-hover:w-3 transition-all"></div>
                          <div className="pl-2">
                            <span className="font-extrabold text-slate-900 block text-lg">{from}</span>
                            <div className="flex items-center gap-2 text-slate-400 my-0.5">
                              <span className="text-[10px] font-black uppercase tracking-tighter italic">Transferring to</span>
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                            </div>
                            <span className="font-extrabold text-orange-600 block text-lg">{to}</span>
                          </div>
                          <div className="text-3xl font-black text-slate-900 font-mono">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-green-50 border-2 border-green-100 rounded-[2.5rem]">
                    <div className="text-4xl mb-2">✅</div>
                    <p className="font-black text-green-700 uppercase text-xs tracking-widest">Everyone is Square!</p>
                  </div>
                )}
              </div>

              <div className="space-y-3 pt-8 border-t-2 border-slate-50">
                <h3 className="text-xs uppercase font-black text-slate-300 tracking-widest">Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center bg-slate-50/50 px-4 py-3 rounded-2xl">
                    <span className="text-slate-600 font-bold">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono font-black text-slate-900">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Total Share</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        <footer className="p-8 bg-slate-50/80 backdrop-blur-md border-t border-slate-100 flex gap-4 sticky bottom-0">
          {step > 1 && (
            <button 
              onClick={prevStep}
              className="flex-1 bg-white border-2 border-slate-100 text-slate-500 font-black py-4 rounded-2xl hover:bg-slate-50 transition-all shadow-sm uppercase text-xs tracking-widest"
            >
              Back
            </button>
          )}
          <button 
            onClick={step === 5 ? () => window.location.reload() : nextStep}
            disabled={step === 1 && friends.length < 2}
            className={`flex-[2] py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.2em] text-white shadow-2xl transition-all ${
              (step === 1 && friends.length < 2) 
                ? 'bg-slate-300 shadow-none grayscale opacity-50' 
                : 'bg-slate-900 hover:bg-black active:scale-95 shadow-slate-200'
            }`}
          >
            {step === 5 ? 'New Split 🍁' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, Settlement, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [tipMode, setTipMode] = useState<'amount' | 'percent'>('percent');
  const [tipPercent, setTipPercent] = useState<number>(15);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [showQuickEntry, setShowQuickEntry] = useState(false);
  const [quickAmount, setQuickAmount] = useState<string>('');

  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id)
    };
    setItems([...items, newItem]);
  };

  const handleQuickTotalAdd = () => {
    const amount = parseFloat(quickAmount);
    if (!isNaN(amount) && amount > 0) {
      addItem("Full Bill Subtotal", amount, TaxCategory.FOOD);
      setQuickAmount('');
      setShowQuickEntry(false);
    }
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const isShared = item.sharedWith.includes(friendId);
        return {
          ...item,
          sharedWith: isShared 
            ? item.sharedWith.filter(id => id !== friendId)
            : [...item.sharedWith, friendId]
        };
      }
      return item;
    }));
  };

  const splitAllEvenly = () => {
    const allFriendIds = friends.map(f => f.id);
    setItems(items.map(item => ({ ...item, sharedWith: [...allFriendIds] })));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setIsScanning(false);
    }
  };

  const calculations = useMemo(() => {
    const totals = calculateItemTotals(items);
    let effectiveTip = tip;
    if (tipMode === 'percent') {
      effectiveTip = totals.subtotal * (tipPercent / 100);
    }
    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip);
    const grandTotal = totals.total + effectiveTip;
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      balances[f.id] = (payments[f.id] || 0) - (itemCosts[f.id] || 0);
    });
    const settlements = solveDebts(balances);
    return { itemCosts, totals, grandTotal, settlements, effectiveTip };
  }, [friends, items, tip, tipMode, tipPercent, payments]);

  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc, curr) => acc + (curr || 0), 0),
    [payments]
  );

  const setSinglePayer = (friendId: string) => {
    const newPayments: Record<string, number> = {};
    friends.forEach(f => {
      newPayments[f.id] = f.id === friendId ? calculations.grandTotal : 0;
    });
    setPayments(newPayments);
  };

  const shareResults = async () => {
    const text = `🤖 Pip Split Report:\n\n` + 
      `Total: $${calculations.grandTotal.toFixed(2)}\n` +
      `-------------------\n` +
      (calculations.settlements.length > 0 
        ? calculations.settlements.map(s => {
          const from = friends.find(f => f.id === s.from)?.name;
          const to = friends.find(f => f.id === s.to)?.name;
          return `• ${from} pays ${to}: $${s.amount.toFixed(2)}`;
        }).join('\n')
        : "Pip says everyone is square! 🤖✅");

    if (navigator.share) {
      try { await navigator.share({ title: 'Pip Split Bill', text }); } catch (err) {}
    } else {
      await navigator.clipboard.writeText(text);
      alert("Beep boop! Copied results to clipboard.");
    }
  };

  return (
    <div className="min-h-screen bg-indigo-50/50 pb-24 md:pb-8 flex justify-center p-2 md:p-4">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:my-4 md:rounded-[3rem] shadow-xl overflow-hidden flex flex-col border border-indigo-100 relative">

        {/* Cute Pip Header */}
        <header className="bg-gradient-to-br from-indigo-500 via-purple-500 to-fuchsia-500 p-8 text-white relative">
          <div className="absolute top-4 right-8 pip-bounce">
            <span className="text-4xl">🤖</span>
          </div>
          <h1 className="text-3xl font-bold tracking-tight">Pip Split</h1>
          <p className="text-indigo-100 text-sm font-medium">Beep boop, let's divide the bill!</p>
        </header>

        <main className="p-6 flex-1 bg-white">
          <StepProgress currentStep={step} />

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="bg-indigo-50 p-4 rounded-3xl border border-indigo-100 flex items-center gap-3">
                <span className="text-2xl">👋</span>
                <p className="text-sm text-indigo-700 font-medium">Hi! Pip is ready to help. Add your dining buddies below!</p>
              </div>
              <div className="relative group">
                <input 
                  type="text" 
                  placeholder="Friend's Name..."
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2rem] px-6 py-4 focus:border-indigo-400 focus:ring-4 focus:ring-indigo-100 outline-none transition-all pr-14 text-lg font-medium"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      addFriend((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
                <button 
                  onClick={() => {
                     const input = document.querySelector('input') as HTMLInputElement;
                     addFriend(input.value);
                     input.value = '';
                  }}
                  className="absolute right-3 top-1/2 -translate-y-1/2 bg-indigo-500 text-white p-2 rounded-full hover:bg-indigo-600 shadow-md"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
                </button>
              </div>
              <div className="grid grid-cols-2 gap-3">
                {friends.map(f => (
                  <div key={f.id} className="bg-white border-2 border-indigo-50 p-4 rounded-3xl flex justify-between items-center group hover:border-indigo-200 hover:shadow-sm transition-all">
                    <span className="font-bold text-slate-700 truncate">{f.name}</span>
                    <button onClick={() => removeFriend(f.id)} className="text-slate-200 hover:text-rose-400 p-1">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 2: ITEMS */}
          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                  <span>📄</span> Bill Details
                </h2>
                <label className="flex items-center gap-2 text-xs text-indigo-600 font-black bg-indigo-50 px-4 py-2 rounded-full cursor-pointer hover:bg-indigo-100 border border-indigo-100 transition-all uppercase tracking-wider">
                  {isScanning ? 'Pip is reading...' : 'Scan Receipt'}
                  <input type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                </label>
              </div>

              {/* Pip's Quick Toggle Entry */}
              <div className="bg-white border-2 border-indigo-100 rounded-[2.5rem] p-6 shadow-sm space-y-4">
                <div className="flex p-1 bg-slate-100 rounded-2xl">
                  <button onClick={() => setShowQuickEntry(false)} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${!showQuickEntry ? 'bg-white shadow-md text-indigo-600' : 'text-slate-400'}`}>Detailed List</button>
                  <button onClick={() => setShowQuickEntry(true)} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${showQuickEntry ? 'bg-white shadow-md text-indigo-600' : 'text-slate-400'}`}>One Big Total</button>
                </div>

                {!showQuickEntry ? (
                  <div className="space-y-3 pt-2">
                    <input id="itemName" type="text" placeholder="What was it? (e.g. Pizza)" className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-4 py-3 text-sm focus:border-indigo-400 outline-none" />
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">$</span>
                        <input id="itemPrice" type="number" placeholder="0.00" className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-6 pr-4 py-3 text-sm focus:border-indigo-400 outline-none" />
                      </div>
                      <select id="itemCat" className="bg-indigo-50 border border-indigo-100 rounded-2xl px-3 py-3 text-[10px] font-black text-indigo-600 uppercase">
                        <option value={TaxCategory.FOOD}>Food</option>
                        <option value={TaxCategory.CONTAINERS}>Takeout</option>
                      </select>
                    </div>
                    <button onClick={() => {
                        const n = document.getElementById('itemName') as HTMLInputElement;
                        const p = document.getElementById('itemPrice') as HTMLInputElement;
                        const c = document.getElementById('itemCat') as HTMLSelectElement;
                        if (n.value && p.value) { addItem(n.value, parseFloat(p.value), c.value as TaxCategory); n.value = ''; p.value = ''; }
                      }} className="w-full bg-indigo-500 text-white font-black py-4 rounded-2xl hover:bg-indigo-600 shadow-lg shadow-indigo-100 transition-all uppercase text-xs tracking-widest">Add to Pip's List</button>
                  </div>
                ) : (
                  <div className="space-y-4 pt-2 text-center animate-in zoom-in-95 duration-200">
                    <div className="text-4xl">⚡️</div>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-tighter">Just one amount? Pip's got you.</p>
                    <div className="relative max-w-[200px] mx-auto">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400 font-bold text-xl">$</span>
                      <input type="number" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} placeholder="Subtotal" className="w-full border-4 border-indigo-50 rounded-[2rem] pl-10 pr-4 py-5 text-2xl font-black text-indigo-600 text-center outline-none focus:border-indigo-200" />
                    </div>
                    <button onClick={handleQuickTotalAdd} className="w-full bg-indigo-600 text-white font-black py-4 rounded-3xl hover:bg-indigo-700 shadow-xl shadow-indigo-100 uppercase text-xs tracking-widest">Split Subtotal Evenly</button>
                  </div>
                )}
              </div>

              <div className="max-h-[30vh] overflow-y-auto space-y-2 pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-4 bg-white border-2 border-indigo-50 rounded-[2rem] shadow-sm group">
                    <div>
                      <p className="font-black text-indigo-900 text-sm truncate max-w-[150px]">{item.name}</p>
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${item.taxCategory === TaxCategory.FOOD ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>{item.taxCategory === TaxCategory.FOOD ? 'Food (5%)' : 'Takeout (12%)'}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="font-mono font-black text-indigo-600">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-200 hover:text-rose-400 p-1"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="flex justify-between items-center bg-indigo-50 p-4 rounded-3xl">
                <div>
                    <h2 className="font-bold text-indigo-900 text-sm">Whose food is it?</h2>
                    <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Tap names to split</p>
                </div>
                <button onClick={splitAllEvenly} className="text-[10px] font-black text-white bg-indigo-500 px-4 py-2 rounded-full uppercase hover:scale-105 transition-all">Split All Even</button>
              </div>

              <div className="space-y-4 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="bg-white border-2 border-indigo-50 rounded-[2.5rem] overflow-hidden shadow-sm">
                    <div className="bg-slate-50/50 px-6 py-3 flex justify-between items-center border-b border-indigo-50">
                      <span className="font-black text-indigo-900 text-sm truncate max-w-[140px]">{item.name}</span>
                      <span className="text-[10px] font-black text-indigo-400 bg-white px-3 py-1 rounded-full border border-indigo-50">${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)} TOTAL</span>
                    </div>
                    <div className="p-4 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button key={f.id} onClick={() => toggleShare(item.id, f.id)} className={`px-4 py-2 rounded-2xl text-[10px] font-black transition-all border-2 uppercase ${item.sharedWith.includes(f.id) ? 'bg-indigo-500 border-indigo-500 text-white shadow-lg' : 'bg-white border-indigo-50 text-indigo-200 hover:border-indigo-100'}`}>{f.name}</button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-6 border-t-2 border-indigo-50">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-xs font-black text-indigo-900 uppercase tracking-widest">Pip's Tip Guide</label>
                  <div className="flex bg-indigo-50 p-1 rounded-2xl border border-indigo-100">
                    <button onClick={() => setTipMode('percent')} className={`px-5 py-2 rounded-xl text-xs font-black ${tipMode === 'percent' ? 'bg-white text-indigo-600 shadow-sm' : 'text-indigo-300'}`}>%</button>
                    <button onClick={() => setTipMode('amount')} className={`px-5 py-2 rounded-xl text-xs font-black ${tipMode === 'amount' ? 'bg-white text-indigo-600 shadow-sm' : 'text-indigo-300'}`}>$</button>
                  </div>
                </div>
                <div className="relative group">
                  <span className={`absolute left-5 top-1/2 -translate-y-1/2 font-black transition-colors ${tipMode === 'amount' ? 'text-indigo-600 text-2xl' : 'hidden'}`}>$</span>
                  <input type="number" value={tipMode === 'percent' ? tipPercent : (tip || '')} onChange={(e) => tipMode === 'percent' ? setTipPercent(parseFloat(e.target.value) || 0) : setTip(parseFloat(e.target.value) || 0)} className={`w-full bg-indigo-50/50 border-4 border-indigo-50 rounded-[2.5rem] py-5 text-3xl font-black text-indigo-600 focus:border-indigo-200 outline-none transition-all text-center ${tipMode === 'amount' ? 'pl-8' : ''}`} />
                  <span className={`absolute right-5 top-1/2 -translate-y-1/2 font-black transition-colors ${tipMode === 'percent' ? 'text-indigo-600 text-3xl' : 'hidden'}`}>%</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-6 animate-in zoom-in-95 duration-500">
              <div className="bg-gradient-to-br from-indigo-600 to-purple-600 p-8 rounded-[3rem] text-white shadow-2xl relative overflow-hidden">
                <div className="absolute -right-4 -top-4 text-7xl opacity-10">💳</div>
                <div className="relative z-10">
                    <p className="text-[10px] font-black text-indigo-100 uppercase tracking-widest mb-1">Total To Match</p>
                    <h3 className="text-4xl font-black italic mb-4">${calculations.grandTotal.toFixed(2)}</h3>
                    <div className="flex justify-between items-center text-xs font-bold bg-white/10 p-3 rounded-2xl">
                        <span>Paid So Far</span>
                        <span className={paidTotal.toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-emerald-300' : 'text-white'}>${paidTotal.toFixed(2)}</span>
                    </div>
                </div>
              </div>

              <div className="space-y-4">
                {friends.map(f => (
                  <div key={f.id} className={`p-5 rounded-[2.5rem] border-4 transition-all flex flex-col gap-3 ${Math.abs((payments[f.id] || 0) - calculations.grandTotal) < 0.01 ? 'border-emerald-400 bg-emerald-50/50' : 'border-indigo-50 bg-white shadow-sm'}`}>
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-2xl bg-indigo-500 flex items-center justify-center text-white font-black text-lg">{f.name[0]}</div>
                            <span className="font-black text-indigo-900 text-lg">{f.name}</span>
                        </div>
                        <div className="relative w-32">
                            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">$</span>
                            <input type="number" value={payments[f.id] || ''} onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})} placeholder="0.00" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl pl-8 pr-4 py-3 text-right font-mono font-black text-indigo-600 text-sm outline-none" />
                        </div>
                    </div>
                    <button onClick={() => setSinglePayer(f.id)} className="w-full bg-indigo-100 text-indigo-600 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-200 transition-all">⚡️ {f.name} Paid Full Bill</button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-8 animate-in zoom-in-95 duration-500 pb-10">
              <div className="text-center">
                <div className="w-24 h-24 bg-indigo-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-indigo-100 shadow-inner">
                    <span className="text-5xl">🥳</span>
                </div>
                <h2 className="text-3xl font-black text-indigo-900">Success!</h2>
                <p className="text-indigo-400 font-bold uppercase text-[10px] tracking-widest mt-1">Pip has solved the puzzle</p>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center px-4">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Payout Instructions</h3>
                  <button onClick={shareResults} className="flex items-center gap-2 bg-indigo-500 text-white px-5 py-3 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 active:scale-95 transition-all">
                    Share Results
                  </button>
                </div>

                {calculations.settlements.length > 0 ? (
                  <div className="space-y-4">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-white p-6 rounded-[2.5rem] flex items-center justify-between border-4 border-indigo-50 shadow-sm relative overflow-hidden group">
                          <div className="absolute left-0 top-0 bottom-0 w-3 bg-gradient-to-b from-indigo-400 to-purple-400"></div>
                          <div className="pl-4">
                            <span className="font-black text-indigo-900 text-lg block leading-none">{from}</span>
                            <div className="flex items-center gap-2 text-indigo-300 my-2">
                              <span className="text-[8px] font-black uppercase tracking-tighter italic">Transferring</span>
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                            </div>
                            <span className="font-black text-indigo-400 text-lg block leading-none">{to}</span>
                          </div>
                          <div className="text-4xl font-black text-indigo-600 font-mono tracking-tighter">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-16 bg-emerald-50 border-4 border-emerald-100 rounded-[3rem]">
                    <div className="text-5xl mb-4">🤖</div>
                    <p className="font-black text-emerald-700 uppercase text-xs tracking-[0.2em]">Pip Says You're All Square!</p>
                  </div>
                )}
              </div>

              <div className="space-y-2 pt-8 border-t-4 border-indigo-50">
                <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-4 mb-4">The Nitty Gritty</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center bg-indigo-50/30 px-6 py-4 rounded-[2rem] border border-indigo-50/50">
                    <span className="text-indigo-900 font-black text-sm uppercase">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono font-black text-indigo-600 text-lg">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                      <p className="text-[7px] font-black text-indigo-300 uppercase tracking-widest">Itemized Total</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        <footer className="p-8 bg-white border-t-4 border-indigo-50 flex gap-4 sticky bottom-0 z-50">
          {step > 1 && (
            <button onClick={prevStep} className="flex-1 bg-white border-4 border-indigo-50 text-indigo-300 font-black py-5 rounded-[2rem] hover:bg-indigo-50 transition-all uppercase text-[10px] tracking-widest">Back</button>
          )}
          <button onClick={step === 5 ? () => window.location.reload() : nextStep} disabled={step === 1 && friends.length < 2} className={`flex-[2] py-5 rounded-[2rem] font-black uppercase text-xs tracking-[0.2em] text-white shadow-2xl transition-all ${ (step === 1 && friends.length < 2) ? 'bg-slate-200 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200' }`}>
            {step === 5 ? 'Start New Trip 🤖' : 'Next Stage'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const RobotIcon = ({ className }: { className?: string }) => (
  <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="11" width="18" height="10" rx="2" />
    <circle cx="12" cy="5" r="2" />
    <path d="M12 7v4" />
    <line x1="8" y1="15" x2="8" y2="15.01" />
    <line x1="16" y1="15" x2="16" y2="15.01" />
  </svg>
);

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [tipMode, setTipMode] = useState<'amount' | 'percent'>('percent');
  const [tipPercent, setTipPercent] = useState<number>(15);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [showQuickEntry, setShowQuickEntry] = useState(false);
  const [quickAmount, setQuickAmount] = useState<string>('');

  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id)
    };
    setItems([...items, newItem]);
  };

  const handleQuickTotalAdd = () => {
    const amount = parseFloat(quickAmount);
    if (!isNaN(amount) && amount > 0) {
      addItem("Full Bill Subtotal", amount, TaxCategory.FOOD);
      setQuickAmount('');
      setShowQuickEntry(false);
    }
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const isShared = item.sharedWith.includes(friendId);
        return {
          ...item,
          sharedWith: isShared 
            ? item.sharedWith.filter(id => id !== friendId)
            : [...item.sharedWith, friendId]
        };
      }
      return item;
    }));
  };

  const splitAllEvenly = () => {
    const allFriendIds = friends.map(f => f.id);
    setItems(items.map(item => ({ ...item, sharedWith: [...allFriendIds] })));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setIsScanning(false);
    }
  };

  const calculations = useMemo(() => {
    const totals = calculateItemTotals(items);
    let effectiveTip = tip;
    if (tipMode === 'percent') {
      effectiveTip = totals.subtotal * (tipPercent / 100);
    }
    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip);
    const grandTotal = totals.total + effectiveTip;
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      balances[f.id] = (payments[f.id] || 0) - (itemCosts[f.id] || 0);
    });
    const settlements = solveDebts(balances);
    return { itemCosts, totals, grandTotal, settlements, effectiveTip };
  }, [friends, items, tip, tipMode, tipPercent, payments]);

  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc, curr) => acc + (curr || 0), 0),
    [payments]
  );

  const setSinglePayer = (friendId: string) => {
    const newPayments: Record<string, number> = {};
    friends.forEach(f => {
      newPayments[f.id] = f.id === friendId ? calculations.grandTotal : 0;
    });
    setPayments(newPayments);
  };

  const shareResults = async () => {
    const text = `🤖 Pip Split Report:\n\n` + 
      `Total: $${calculations.grandTotal.toFixed(2)}\n` +
      `-------------------\n` +
      (calculations.settlements.length > 0 
        ? calculations.settlements.map(s => {
          const from = friends.find(f => f.id === s.from)?.name;
          const to = friends.find(f => f.id === s.to)?.name;
          return `• ${from} pays ${to}: $${s.amount.toFixed(2)}`;
        }).join('\n')
        : "Pip says everyone is square! 🤖✅");

    if (navigator.share) {
      try { await navigator.share({ title: 'Pip Split Bill', text }); } catch (err) {}
    } else {
      await navigator.clipboard.writeText(text);
      alert("Results copied to clipboard! (Beep boop)");
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 flex justify-center p-0 md:p-8">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col border border-slate-200 relative">

        {/* Polished Pip Header */}
        <header className="bg-indigo-600 p-8 text-white relative">
          <div className="absolute top-8 right-8 pip-bounce opacity-80">
            <RobotIcon className="w-12 h-12" />
          </div>
          <div className="relative z-10">
            <h1 className="text-3xl font-black tracking-tight flex items-center gap-3">
              Pip Split
            </h1>
            <p className="text-indigo-100 text-sm font-medium mt-1">Calculated bill splitting with Pip the Robot</p>
          </div>
        </header>

        <main className="p-6 flex-1 bg-white">
          <StepProgress currentStep={step} />

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 flex items-center gap-4">
                <div className="p-2 bg-indigo-100 rounded-xl text-indigo-600">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z"/></svg>
                </div>
                <p className="text-sm text-slate-600 font-medium">Add everyone who's sharing the bill today.</p>
              </div>
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Enter name..."
