                  <div className="space-y-3">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-white p-6 rounded-[2rem] flex items-center justify-between border-2 border-slate-100 shadow-sm relative overflow-hidden">
                          <div className="absolute left-0 top-0 bottom-0 w-2 bg-indigo-600"></div>
                          <div className="pl-2">
                            <span className="font-black text-slate-800 text-lg block leading-none">{from}</span>
                            <div className="flex items-center gap-2 text-slate-300 my-2">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>
                            </div>
                            <span className="font-black text-indigo-600 text-lg block leading-none">{to}</span>
                          </div>
                          <div className="text-3xl font-black text-slate-900 font-mono tracking-tighter">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-16 bg-slate-50 border-2 border-dashed border-slate-200 rounded-[2.5rem]">
                    <RobotIcon className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                    <p className="font-black text-slate-400 uppercase text-xs tracking-widest">Everyone is settled!</p>
                  </div>
                )}
              </div>

              <div className="space-y-2 pt-6 border-t border-slate-100">
                <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-widest px-2 mb-3">Share Breakdown</h3>
                {friends.map(f => (
                  <div key={f.id} className="flex justify-between items-center bg-slate-50 px-5 py-4 rounded-2xl border border-slate-100">
                    <span className="text-slate-700 font-black text-sm uppercase">{f.name}</span>
                    <div className="text-right">
                      <span className="font-mono font-black text-slate-900 text-lg">${(calculations.itemCosts[f.id] || 0).toFixed(2)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>

        <footer className="p-8 bg-white border-t border-slate-100 flex gap-4 sticky bottom-0 z-50">
          {step > 1 && (
            <button onClick={prevStep} className="flex-1 bg-white border-2 border-slate-200 text-slate-400 font-black py-4 rounded-2xl hover:bg-slate-50 transition-all uppercase text-[10px] tracking-widest">Back</button>
          )}
          <button onClick={step === 5 ? () => window.location.reload() : nextStep} disabled={step === 1 && friends.length < 2} className={`flex-[2] py-4 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl transition-all ${ (step === 1 && friends.length < 2) ? 'bg-slate-300 shadow-none grayscale opacity-50' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-[0.98]' }`}>
            {step === 5 ? 'New Split' : 'Continue'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React from 'react';

interface StepProgressProps {
  currentStep: number;
  onStepClick: (step: number) => void;
}

const StepProgress: React.FC<StepProgressProps> = ({ currentStep, onStepClick }) => {
  const steps = ["Friends", "Items", "Split", "Payments", "Results"];

  return (
    <div className="flex items-center justify-between mb-8 px-2 overflow-x-auto no-scrollbar">
      {steps.map((label, index) => {
        const stepNumber = index + 1;
        const isActive = currentStep === stepNumber;
        const isCompleted = currentStep > stepNumber;

        return (
          <React.Fragment key={label}>
            <button 
              onClick={() => onStepClick(stepNumber)}
              className="flex flex-col items-center min-w-[60px] outline-none group"
            >
              <div className={`w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold transition-all transform group-active:scale-90 ${
                isActive ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 
                isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-200 text-slate-500 hover:bg-slate-300'
              }`}>
                {isCompleted ? (
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
                ) : stepNumber}
              </div>
              <span className={`text-[10px] uppercase mt-2 font-bold tracking-tight transition-colors ${
                isActive ? 'text-indigo-600' : 'text-slate-400'
              }`}>
                {label}
              </span>
            </button>
            {index < steps.length - 1 && (
              <div className={`flex-1 h-[2px] mx-1 mb-6 transition-colors ${
                isCompleted ? 'bg-emerald-200' : 'bg-slate-100'
              }`} />
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
};

export default StepProgress;

import React, { useState, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';
import { scanBillWithGemini } from './services/geminiService';

const BotIcon = ({ className }: { className?: string }) => (
  <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="11" width="18" height="10" rx="2" />
    <circle cx="12" cy="5" r="2" />
    <path d="M12 7v4" />
    <line x1="8" y1="15" x2="8" y2="15.01" />
    <line x1="16" y1="15" x2="16" y2="15.01" />
  </svg>
);

const App: React.FC = () => {
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [tip, setTip] = useState<number>(0);
  const [tipMode, setTipMode] = useState<'amount' | 'percent'>('percent');
  const [tipPercent, setTipPercent] = useState<number>(15);
  const [payments, setPayments] = useState<Record<string, number>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [showQuickEntry, setShowQuickEntry] = useState(false);
  const [quickAmount, setQuickAmount] = useState<string>('');

  const nextStep = () => setStep(s => Math.min(s + 1, 5));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));
  const goToStep = (s: number) => setStep(s);

  const addFriend = (name: string) => {
    if (!name.trim()) return;
    const newFriend = { id: Math.random().toString(36).substr(2, 9), name };
    setFriends([...friends, newFriend]);
  };

  const removeFriend = (id: string) => {
    setFriends(friends.filter(f => f.id !== id));
    setItems(items.map(item => ({
      ...item,
      sharedWith: item.sharedWith.filter(fid => fid !== id)
    })));
  };

  const addItem = (name: string, price: number, taxCategory: TaxCategory) => {
    const newItem = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      price,
      taxCategory,
      sharedWith: friends.map(f => f.id)
    };
    setItems([...items, newItem]);
  };

  const handleQuickTotalAdd = () => {
    const amount = parseFloat(quickAmount);
    if (!isNaN(amount) && amount > 0) {
      addItem("Lump Sum Total", amount, TaxCategory.FOOD);
      setQuickAmount('');
      setShowQuickEntry(false);
    }
  };

  const removeItem = (id: string) => {
    setItems(items.filter(i => i.id !== id));
  };

  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map(item => {
      if (item.id === itemId) {
        const isShared = item.sharedWith.includes(friendId);
        return {
          ...item,
          sharedWith: isShared 
            ? item.sharedWith.filter(id => id !== friendId)
            : [...item.sharedWith, friendId]
        };
      }
      return item;
    }));
  };

  const splitAllEvenly = () => {
    const allFriendIds = friends.map(f => f.id);
    setItems(items.map(item => ({ ...item, sharedWith: [...allFriendIds] })));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        const extracted = await scanBillWithGemini(base64);
        const mappedItems = extracted.map((i: any) => ({
          ...i,
          id: Math.random().toString(36).substr(2, 9),
          sharedWith: friends.map(f => f.id)
        }));
        setItems(prev => [...prev, ...mappedItems]);
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setIsScanning(false);
    }
  };

  const calculations = useMemo(() => {
    const totals = calculateItemTotals(items);
    let effectiveTip = tip;
    if (tipMode === 'percent') {
      effectiveTip = totals.subtotal * (tipPercent / 100);
    }
    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip);
    const grandTotal = totals.total + effectiveTip;
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      balances[f.id] = (payments[f.id] || 0) - (itemCosts[f.id] || 0);
    });
    const settlements = solveDebts(balances);
    return { itemCosts, totals, grandTotal, settlements, effectiveTip };
  }, [friends, items, tip, tipMode, tipPercent, payments]);

  const paidTotal = useMemo(() => 
    (Object.values(payments) as number[]).reduce((acc, curr) => acc + (curr || 0), 0),
    [payments]
  );

  const setSinglePayer = (friendId: string) => {
    const newPayments: Record<string, number> = {};
    friends.forEach(f => {
      newPayments[f.id] = f.id === friendId ? calculations.grandTotal : 0;
    });
    setPayments(newPayments);
  };

  const shareResults = async () => {
    const text = `🤖 SplitBot Results:\n\n` + 
      `Total Bill: $${calculations.grandTotal.toFixed(2)}\n` +
      `-------------------\n` +
      (calculations.settlements.length > 0 
        ? calculations.settlements.map(s => {
          const from = friends.find(f => f.id === s.from)?.name;
          const to = friends.find(f => f.id === s.to)?.name;
          return `• ${from} pays ${to}: $${s.amount.toFixed(2)}`;
        }).join('\n')
        : "SplitBot says everyone is settled! ✅");

    if (navigator.share) {
      try { await navigator.share({ title: 'SplitBot Report', text }); } catch (err) {}
    } else {
      await navigator.clipboard.writeText(text);
      alert("Results copied to clipboard! (Beep boop)");
    }
  };

  // SplitBot speech helper
  const getBotSpeech = () => {
    switch (step) {
      case 1: return "Hello! Who are we splitting the bill with today?";
      case 2: return "Let's record everything that was ordered. You can even scan the receipt!";
      case 3: return "Time to assign the items. Tap a name to add someone to the split!";
      case 4: return "Almost there! Tell me who paid what on the final bill.";
      case 5: return "Calculation complete! Here is the most efficient way to settle up.";
      default: return "Beep boop!";
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 flex justify-center p-0 md:p-8">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col border border-slate-200 relative">

        {/* Header */}
        <header className="bg-indigo-700 px-8 py-10 text-white relative overflow-hidden">
          <div className="absolute top-10 right-8 bot-float opacity-30">
            <BotIcon className="w-16 h-16" />
          </div>
          <div className="relative z-10">
            <h1 className="text-4xl font-black tracking-tight flex items-center gap-3">
              SplitBot
            </h1>
            <p className="text-indigo-200 text-xs font-bold uppercase tracking-[0.2em] mt-1">Efficient Bill Splitting</p>
          </div>
        </header>

        <main className="p-6 flex-1 bg-white flex flex-col">
          <StepProgress currentStep={step} onStepClick={goToStep} />

          {/* SplitBot Speech Area - No box as requested */}
          <div className="mb-8 flex items-start gap-4 animate-in fade-in slide-in-from-top-2 duration-700">
            <div className="p-2.5 bg-indigo-50 rounded-2xl text-indigo-600 shrink-0">
              <BotIcon className="w-6 h-6" />
            </div>
            <div className="pt-1">
              <p className="text-lg font-bold text-slate-800 leading-tight">
                {getBotSpeech()}
              </p>
            </div>
          </div>

          {/* STEP 1: FRIENDS */}
          {step === 1 && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Enter a name..."
                  className="w-full bg-white border-2 border-slate-100 rounded-2xl px-6 py-4 focus:border-indigo-500 outline-none transition-all pr-14 text-lg font-bold shadow-sm"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      addFriend((e.target as HTMLInputElement).value);
                      (e.target as HTMLInputElement).value = '';
                    }
                  }}
                />
                <button 
                  onClick={() => {
                     const input = document.querySelector('input') as HTMLInputElement;
                     addFriend(input.value);
                     input.value = '';
                  }}
                  className="absolute right-3 top-1/2 -translate-y-1/2 bg-indigo-600 text-white p-2.5 rounded-xl hover:bg-indigo-700 shadow-md transition-all active:scale-95"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"/></svg>
                </button>
              </div>
              <div className="grid grid-cols-2 gap-3">
                {friends.map(f => (
                  <div key={f.id} className="bg-slate-50 border border-slate-100 p-4 rounded-2xl flex justify-between items-center group hover:border-indigo-300 transition-all">
                    <span className="font-bold text-slate-700 truncate">{f.name}</span>
                    <button onClick={() => removeFriend(f.id)} className="text-slate-400 hover:text-rose-500 transition-colors">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 2: ITEMS */}
          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">Entry List</h2>
                <label className="flex items-center gap-2 text-xs text-indigo-600 font-bold bg-indigo-50 px-4 py-2 rounded-xl cursor-pointer hover:bg-indigo-100 border border-indigo-200 transition-all">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                  {isScanning ? 'Scanning...' : 'Scan Bill'}
                  <input type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
                </label>
              </div>

              <div className="bg-slate-50 border border-slate-200 rounded-3xl p-5 space-y-4 shadow-inner">
                <div className="flex p-1 bg-slate-200 rounded-xl">
                  <button onClick={() => setShowQuickEntry(false)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${!showQuickEntry ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500'}`}>Detailed</button>
                  <button onClick={() => setShowQuickEntry(true)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${showQuickEntry ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500'}`}>Lump Sum</button>
                </div>

                {!showQuickEntry ? (
                  <div className="space-y-3">
                    <input id="itemName" type="text" placeholder="Item Name" className="w-full bg-white border border-slate-300 rounded-xl px-4 py-3 text-sm focus:border-indigo-500 outline-none font-bold" />
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">$</span>
                        <input id="itemPrice" type="number" placeholder="0.00" className="w-full bg-white border border-slate-300 rounded-xl pl-6 pr-4 py-3 text-sm focus:border-indigo-500 outline-none font-mono" />
                      </div>
                      <select id="itemCat" className="bg-white border border-slate-300 rounded-xl px-3 py-3 text-xs font-bold text-slate-600">
                        <option value={TaxCategory.FOOD}>Food (5%)</option>
                        <option value={TaxCategory.CONTAINERS}>Takeout (12%)</option>
                      </select>
                    </div>
                    <button onClick={() => {
                        const n = document.getElementById('itemName') as HTMLInputElement;
                        const p = document.getElementById('itemPrice') as HTMLInputElement;
                        const c = document.getElementById('itemCat') as HTMLSelectElement;
                        if (n.value && p.value) { addItem(n.value, parseFloat(p.value), c.value as TaxCategory); n.value = ''; p.value = ''; }
                      }} className="w-full bg-indigo-600 text-white font-bold py-3.5 rounded-xl hover:bg-indigo-700 transition-all active:scale-[0.98] shadow-lg shadow-indigo-100">Add Item</button>
                  </div>
                ) : (
                  <div className="space-y-4 py-2 animate-in fade-in zoom-in-95 duration-200">
                    <div className="relative max-w-[200px] mx-auto">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-600 font-black text-xl">$</span>
                      <input type="number" value={quickAmount} onChange={(e) => setQuickAmount(e.target.value)} placeholder="0.00" className="w-full border-2 border-slate-300 rounded-2xl pl-10 pr-4 py-4 text-2xl font-black text-slate-800 text-center focus:border-indigo-500 outline-none transition-all shadow-sm" />
                    </div>
                    <button onClick={handleQuickTotalAdd} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl hover:bg-indigo-700 transition-all shadow-xl">Apply Total</button>
                  </div>
                )}
              </div>

              <div className="max-h-[35vh] overflow-y-auto space-y-2 pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm hover:border-indigo-200 transition-all group">
                    <div>
                      <p className="font-bold text-slate-800 text-sm">{item.name}</p>
                      <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-md ${item.taxCategory === TaxCategory.FOOD ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>{item.taxCategory === TaxCategory.FOOD ? 'GST 5%' : 'GST+PST 12%'}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="font-mono font-black text-slate-900">${item.price.toFixed(2)}</span>
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 3: SPLIT */}
          {step === 3 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
              <div className="flex justify-between items-center">
                <h2 className="text-xs font-black text-slate-400 uppercase tracking-widest">Share Mapping</h2>
                <button onClick={splitAllEvenly} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-200 uppercase hover:bg-indigo-600 hover:text-white transition-all">Split Evenly</button>
              </div>

              <div className="space-y-4 max-h-[45vh] overflow-y-auto pr-1 no-scrollbar">
                {items.map(item => (
                  <div key={item.id} className="bg-white border border-slate-100 rounded-3xl overflow-hidden shadow-sm hover:border-indigo-200 transition-all">
                    <div className="bg-slate-50 px-5 py-3 flex justify-between items-center border-b border-slate-100">
                      <span className="font-bold text-slate-800 text-sm truncate">{item.name}</span>
                      <span className="text-[10px] font-black text-slate-500 bg-white px-3 py-1 rounded-lg border border-slate-200">${(item.price * (1 + GST_RATE + (item.taxCategory === TaxCategory.CONTAINERS ? PST_RATE : 0))).toFixed(2)} Total</span>
                    </div>
                    <div className="p-4 flex flex-wrap gap-2">
                      {friends.map(f => (
                        <button key={f.id} onClick={() => toggleShare(item.id, f.id)} className={`px-4 py-2 rounded-xl text-xs font-black transition-all border-2 ${item.sharedWith.includes(f.id) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-100 text-slate-400 hover:border-indigo-300'}`}>{f.name}</button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-6 border-t-2 border-slate-100">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Add a Tip</label>
                  <div className="flex bg-slate-100 p-1 rounded-xl">
                    <button onClick={() => setTipMode('percent')} className={`px-4 py-1.5 rounded-lg text-xs font-black ${tipMode === 'percent' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>%</button>
                    <button onClick={() => setTipMode('amount')} className={`px-4 py-1.5 rounded-lg text-xs font-black ${tipMode === 'amount' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>$</button>
                  </div>
                </div>
                <div className="relative">
                  <span className={`absolute left-5 top-1/2 -translate-y-1/2 font-black text-xl transition-colors ${tipMode === 'amount' ? 'text-indigo-600' : 'hidden'}`}>$</span>
                  <input type="number" value={tipMode === 'percent' ? tipPercent : (tip || '')} onChange={(e) => tipMode === 'percent' ? setTipPercent(parseFloat(e.target.value) || 0) : setTip(parseFloat(e.target.value) || 0)} className={`w-full bg-slate-50 border-2 border-slate-200 rounded-2xl py-4 text-3xl font-black text-indigo-600 text-center focus:border-indigo-500 outline-none transition-all shadow-sm ${tipMode === 'amount' ? 'pl-8' : ''}`} />
                  <span className={`absolute right-5 top-1/2 -translate-y-1/2 font-black text-2xl transition-colors ${tipMode === 'percent' ? 'text-indigo-600' : 'hidden'}`}>%</span>
                </div>
              </div>
            </div>
          )}

          {/* STEP 4: PAYMENTS */}
          {step === 4 && (
            <div className="space-y-6 animate-in zoom-in-95 duration-500">
              <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
                <div className="absolute -right-8 -top-8 text-indigo-500 opacity-20">
                  <svg className="w-32 h-32" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z"/></svg>
                </div>
                <div className="relative z-10">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Target Total</p>
                    <h3 className="text-4xl font-black mb-6">${calculations.grandTotal.toFixed(2)}</h3>
                    <div className="flex justify-between items-center text-xs font-bold border-t border-white/10 pt-4">
                        <span className="opacity-60 uppercase">Currently Recorded</span>
                        <span className={`text-lg font-mono ${paidTotal.toFixed(2) === calculations.grandTotal.toFixed(2) ? 'text-emerald-400' : 'text-white'}`}>${paidTotal.toFixed(2)}</span>
                    </div>
                </div>
              </div>

              <div className="space-y-4">
                {friends.map(f => (
                  <div key={f.id} className={`p-4 rounded-[2rem] border-2 transition-all ${Math.abs((payments[f.id] || 0) - calculations.grandTotal) < 0.01 ? 'border-indigo-500 bg-indigo-50/50' : 'border-slate-100 bg-white shadow-sm'}`}>
                    <div className="flex items-center justify-between mb-3 px-2">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center font-black text-slate-600">{f.name[0]}</div>
                            <span className="font-bold text-slate-800">{f.name}</span>
                        </div>
                        <div className="relative w-32">
                            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">$</span>
                            <input type="number" value={payments[f.id] || ''} onChange={(e) => setPayments({...payments, [f.id]: parseFloat(e.target.value) || 0})} placeholder="0.00" className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-8 pr-4 py-3 text-right font-mono font-black text-slate-900 text-sm outline-none focus:border-indigo-500" />
                        </div>
                    </div>
                    <button onClick={() => setSinglePayer(f.id)} className="w-full bg-indigo-600 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 active:scale-95">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
                        {f.name} Paid Full Bill
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* STEP 5: RESULTS */}
          {step === 5 && (
            <div className="space-y-10 animate-in zoom-in-95 duration-500 flex-1 flex flex-col">
              <div className="text-center">
                <div className="w-24 h-24 bg-indigo-600 rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-indigo-100 text-white mb-6">
                    <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
                </div>
                <h2 className="text-3xl font-black text-slate-800 tracking-tight">Settlements</h2>
              </div>

              <div className="space-y-4 flex-1">
                {calculations.settlements.length > 0 ? (
                  <div className="space-y-4">
                    {calculations.settlements.map((s, idx) => {
                      const from = friends.find(f => f.id === s.from)?.name;
                      const to = friends.find(f => f.id === s.to)?.name;
                      return (
                        <div key={idx} className="bg-slate-50 p-6 rounded-[2.5rem] flex items-center justify-between border border-slate-100 shadow-sm relative group hover:border-indigo-300 transition-all">
                          <div className="flex-1">
                            <span className="font-black text-slate-900 text-xl block leading-none">{from}</span>
                            <div className="flex items-center gap-3 text-slate-400 my-4">
                              <span className="text-[10px] font-black uppercase tracking-widest opacity-50">Pays to</span>
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
                            </div>
                            <span className="font-black text-indigo-600 text-xl block leading-none">{to}</span>
                          </div>
                          <div className="text-4xl font-black text-slate-900 font-mono tracking-tighter">
                            ${s.amount.toFixed(2)}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-20 bg-slate-50 border-2 border-dashed border-slate-200 rounded-[3rem]">
                    <BotIcon className="w-16 h-16 text-slate-200 mx-auto mb-4" />
                    <p className="font-black text-slate-400 uppercase text-sm tracking-widest">No transfers needed!</p>
                  </div>
                )}
              </div>

              <div className="pt-4">
                <button onClick={shareResults} className="w-full flex items-center justify-center gap-3 bg-indigo-600 text-white px-8 py-5 rounded-[2rem] text-sm font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
                  Share Instructions
                </button>
              </div>
            </div>
          )}
        </main>

        <footer className="p-8 bg-white border-t border-slate-100 flex gap-4 sticky bottom-0 z-50">
          {step > 1 && (
            <button onClick={prevStep} className="flex-1 bg-white border-2 border-slate-200 text-slate-400 font-black py-4 rounded-2xl hover:bg-slate-50 transition-all uppercase text-[10px] tracking-widest">Back</button>
          )}
          <button onClick={step === 5 ? () => window.location.reload() : nextStep} disabled={step === 1 && friends.length < 2} className={`flex-[2] py-4 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl transition-all ${ (step === 1 && friends.length < 2) ? 'bg-slate-300 shadow-none grayscale opacity-50' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-[0.98]' }`}>
            {step === 5 ? 'New Split Bot 🤖' : 'Next Step'}
          </button>
        </footer>
      </div>
    </div>
  );
};

export default App;

export enum TaxCategory {
  FOOD = 'FOOD', // GST only (5%)
  CONTAINERS = 'CONTAINERS' // GST (5%) + PST (7%)
}

export interface Friend {
  id: string;
  name: string;
  partnerId?: string; // ID of another friend to group as a couple
}

export interface BillItem {
  id: string;
  name: string;
  price: number;
  taxCategory: TaxCategory;
  sharedWith: string[]; // Array of Friend IDs
  isTaxIncluded?: boolean; // If true, don't add 5/12% tax on top
}

export interface PaymentRecord {
  friendId: string;
  amount: number;
}

export interface Settlement {
  from: string; // Friend ID (or Couple name/combined ID string)
  to: string;   // Friend ID
  amount: number;
  isFromCouple?: boolean;
  isToCouple?: boolean;
  coupleNames?: string;
}

export const GST_RATE = 0.05;
export const PST_RATE = 0.07;

import { BillItem, Friend, TaxCategory, GST_RATE, PST_RATE, Settlement } from '../types';

export const calculateItemTotals = (items: BillItem[]) => {
  let subtotal = 0;
  let gst = 0;
  let pst = 0;

  items.forEach(item => {
    subtotal += item.price;
    if (!item.isTaxIncluded) {
      gst += item.price * GST_RATE;
      if (item.taxCategory === TaxCategory.CONTAINERS) {
        pst += item.price * PST_RATE;
      }
    }
  });

  return { subtotal, gst, pst, total: subtotal + gst + pst };
};

export const calculateIndividualCosts = (
  friends: Friend[],
  items: BillItem[],
  tipAmount: number
) => {
  const { total: billTotal } = calculateItemTotals(items);
  const costMap: Record<string, number> = {};

  friends.forEach(f => costMap[f.id] = 0);

  items.forEach(item => {
    if (item.sharedWith.length === 0) return;

    let itemTotal = item.price;
    if (!item.isTaxIncluded) {
      const itemGst = item.price * GST_RATE;
      const itemPst = item.taxCategory === TaxCategory.CONTAINERS ? item.price * PST_RATE : 0;
      itemTotal = item.price + itemGst + itemPst;
    }

    const share = itemTotal / item.sharedWith.length;
    item.sharedWith.forEach(friendId => {
      costMap[friendId] += share;
    });
  });

  // Distribute tip proportionally to the share of the bill
  if (billTotal > 0) {
    friends.forEach(f => {
      const proportion = costMap[f.id] / billTotal;
      costMap[f.id] += proportion * tipAmount;
    });
  }

  return costMap;
};

export const solveDebts = (
  balances: Record<string, number>,
  friends: Friend[]
): Settlement[] => {
  const settleList: Settlement[] = [];

  // Merge balances for couples
  const processedBalances: Record<string, number> = {};
  const processedFriendIds = new Set<string>();
  const couplesMap: Record<string, string> = {}; // combinedId -> display name

  friends.forEach(f => {
    if (processedFriendIds.has(f.id)) return;

    if (f.partnerId) {
      const partner = friends.find(p => p.id === f.partnerId);
      if (partner) {
        const combinedId = `couple_${f.id}_${partner.id}`;
        processedBalances[combinedId] = (balances[f.id] || 0) + (balances[partner.id] || 0);
        couplesMap[combinedId] = `${f.name} & ${partner.name}`;
        processedFriendIds.add(f.id);
        processedFriendIds.add(partner.id);
      } else {
        processedBalances[f.id] = balances[f.id] || 0;
        processedFriendIds.add(f.id);
      }
    } else {
      processedBalances[f.id] = balances[f.id] || 0;
      processedFriendIds.add(f.id);
    }
  });

  const credit = Object.keys(processedBalances)
    .filter(id => processedBalances[id] > 0.01)
    .sort((a, b) => processedBalances[b] - processedBalances[a]);
  const debit = Object.keys(processedBalances)
    .filter(id => processedBalances[id] < -0.01)
    .sort((a, b) => processedBalances[a] - processedBalances[b]);

  let i = 0, j = 0;
  const tempBalances = { ...processedBalances };

  while (i < credit.length && j < debit.length) {
    const creditor = credit[i];
    const debtor = debit[j];
    const amount = Math.min(tempBalances[creditor], -tempBalances[debtor]);

    if (amount > 0.01) {
      settleList.push({
        from: debtor,
        to: creditor,
        amount: Number(amount.toFixed(2)),
        isFromCouple: debtor.startsWith('couple_'),
        isToCouple: creditor.startsWith('couple_'),
        coupleNames: debtor.startsWith('couple_') ? couplesMap[debtor] : (creditor.startsWith('couple_') ? couplesMap[creditor] : undefined)
      });
    }

    tempBalances[creditor] -= amount;
    tempBalances[debtor] += amount;

    if (tempBalances[creditor] < 0.01) i++;
    if (tempBalances[debtor] > -0.01) j++;
  }

  return settleList;
};

import React, { useState, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
