                </button>
                {showCoupleHint && (
                  <p className="mt-2 text-[10px] text-slate-500 font-medium leading-relaxed animate-in fade-in slide-in-from-top-1 duration-200">
                    Linking two people combines their debt. They will be treated as one unit in the final results. Tap the heart to start linking!
                  </p>
                )}
              </div>

              {linkingFriendId && <div className="text-center animate-pulse text-xs font-bold text-indigo-500 uppercase tracking-widest bg-indigo-50 py-2 rounded-xl">Select another person to link with</div>}
            </div>
