const SplitView = ({ items, friends, setItems, billConfig, setBillConfig, effectiveTip }: any) => {
  const toggleShare = (itemId: string, friendId: string) => {
    setItems(items.map((item: BillItem) => {
      if (item.id === itemId) {
        const isShared = item.sharedWith.includes(friendId);
        return {
          ...item,
          sharedWith: isShared 
            ? item.sharedWith.filter(id => id !== friendId)
            : [...item.sharedWith, friendId]
        };
      }
      return item;
    }));
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
       <div className="space-y-4 max-h-[40vh] overflow-y-auto no-scrollbar">
        {items.map((item: BillItem) => (
          <div key={item.id} className="bg-white border border-slate-100 rounded-3xl overflow-hidden shadow-sm">
            <div className="bg-slate-50 px-5 py-3 flex justify-between items-center border-b">
              <span className="font-bold text-slate-800 text-sm">{item.name}</span>
              <span className="text-[10px] font-black text-slate-500">${item.price.toFixed(2)}</span>
            </div>
            <div className="p-4 flex flex-wrap gap-2">
              {friends.map((f: Friend) => (
                <button 
                  key={f.id} 
                  onClick={() => toggleShare(item.id, f.id)} 
                  className={`px-4 py-2 rounded-xl text-xs font-black transition-all border-2 ${item.sharedWith.includes(f.id) ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}
                >
                  {f.name}
                </button>
              ))}
            </div>
          </div>
        ))}
      </div>

      <div className="pt-4 border-t-2 border-slate-100 space-y-4">
         <div className="flex justify-between items-center">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Bill Tip</label>
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <button onClick={() => setBillConfig({...billConfig, tipMode: 'percent'})} className={`px-2 py-1.5 rounded-lg text-[9px] font-black ${billConfig.tipMode === 'percent' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>%</button>
              <button onClick={() => setBillConfig({...billConfig, tipMode: 'amount'})} className={`px-2 py-1.5 rounded-lg text-[9px] font-black ${billConfig.tipMode === 'amount' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>$</button>
              <button onClick={() => setBillConfig({...billConfig, tipMode: 'total'})} className={`px-2 py-1.5 rounded-lg text-[9px] font-black ${billConfig.tipMode === 'total' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>Final Bill</button>
            </div>
         </div>
         <input 
            type="number" 
            value={billConfig.tipMode === 'percent' ? billConfig.tipPercent : billConfig.tipMode === 'amount' ? billConfig.tip : billConfig.manualGrandTotal}
            onChange={(e) => {
              const val = parseFloat(e.target.value) || 0;
              if (billConfig.tipMode === 'percent') setBillConfig({...billConfig, tipPercent: val});
              else if (billConfig.tipMode === 'amount') setBillConfig({...billConfig, tip: val});
              else setBillConfig({...billConfig, manualGrandTotal: val});
            }}
            className="w-full bg-slate-50 border-2 border-slate-200 rounded-xl py-3 text-xl font-black text-indigo-600 text-center" 
         />
         {billConfig.tipMode === 'total' && <p className="text-[10px] text-center text-slate-400">Tip automatically calculated: ${effectiveTip.toFixed(2)}</p>}
      </div>
    </div>
  );
};

