  switch (step) {
    case 1: return "Hello! Who are we splitting the bill with today? Tap the heart icon to link a couple!";
    case 2: return "Record your items. You can scan the receipt with Gemini AI to save time!";
    case 3: return "Tap names to assign each item. I'll handle the tax and proportions!";
    case 4: return "Who paid the bill? If one person paid everything, enter it under their name.";
