{
  "name": "Restaurant Bill Bot",
  "description": "A sophisticated restaurant bill splitter designed for BC, Canada, handling GST/PST tax rules and complex itemized splits with friend-to-friend debt resolution and couple functionality.",
  "requestFramePermissions": []
}

import React, { useState, useMemo } from 'react';
import { Friend, BillItem, TaxCategory, GST_RATE, PST_RATE } from './types';
import { calculateIndividualCosts, solveDebts, calculateItemTotals } from './utils/finance';
import StepProgress from './components/StepProgress';

// --- Shared Icons ---
const BotIcon = ({ className }: { className?: string }) => (
  <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="11" width="18" height="10" rx="2" />
    <circle cx="12" cy="5" r="2" />
    <path d="M12 7v4" />
    <line x1="8" y1="15" x2="8" y2="15.01" />
    <line x1="16" y1="15" x2="16" y2="15.01" />
  </svg>
);

const HeartIcon = ({ className }: { className?: string }) => (
  <svg className={className} fill="currentColor" viewBox="0 0 24 24"><path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg>
);

const App: React.FC = () => {
  // --- State ---
  const [step, setStep] = useState(1);
  const [friends, setFriends] = useState<Friend[]>([]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [etransferEmail, setEtransferEmail] = useState('');
  const [payments, setPayments] = useState<Record<string, number>>({});

  // Bill Settings State
  const [billConfig, setBillConfig] = useState({
    tip: 0,
    tipPercent: 15,
    tipMode: 'percent' as 'amount' | 'percent' | 'total',
    discount: 0,
    discountPercent: 0,
    discountMode: 'amount' as 'amount' | 'percent',
    manualGrandTotal: 0
  });

  // UI State
  const [linkingFriendId, setLinkingFriendId] = useState<string | null>(null);
  const [copyFeedback, setCopyFeedback] = useState(false);

  // --- Calculations ---
  const totals = useMemo(() => calculateItemTotals(items), [items]);

  const effectiveDiscount = useMemo(() => {
    return billConfig.discountMode === 'percent' 
      ? totals.subtotal * (billConfig.discountPercent / 100) 
      : billConfig.discount;
  }, [totals.subtotal, billConfig.discountMode, billConfig.discount, billConfig.discountPercent]);

  const effectiveTip = useMemo(() => {
    if (billConfig.tipMode === 'percent') return totals.subtotal * (billConfig.tipPercent / 100);
    if (billConfig.tipMode === 'total') return Math.max(0, billConfig.manualGrandTotal - totals.total + effectiveDiscount);
    return billConfig.tip;
  }, [totals.subtotal, totals.total, billConfig, effectiveDiscount]);

  const grandTotal = useMemo(() => totals.total + effectiveTip - effectiveDiscount, [totals.total, effectiveTip, effectiveDiscount]);

  const settlements = useMemo(() => {
    const netAdjustment = effectiveTip - effectiveDiscount;
    const itemCosts = calculateIndividualCosts(friends, items, netAdjustment);
    const balances: Record<string, number> = {};
    friends.forEach(f => {
      balances[f.id] = (payments[f.id] || 0) - (itemCosts[f.id] || 0);
    });
    return solveDebts(balances, friends);
  }, [friends, items, effectiveTip, effectiveDiscount, payments]);

  // --- Handlers ---
  const handleNext = () => setStep(s => Math.min(s + 1, 5));
  const handlePrev = () => setStep(s => Math.max(s - 1, 1));

  const generateReportText = () => {
    const itemCosts = calculateIndividualCosts(friends, items, effectiveTip - effectiveDiscount);
    let text = `Total Bill: $${grandTotal.toFixed(2)}\n`;
    text += `-------------------\n`;
    if (settlements.length > 0) {
      text += `SETTLEMENTS:\n`;
      text += settlements.map(s => `• ${s.fromName} pays ${s.toName}: $${s.amount.toFixed(2)}`).join('\n') + `\n`;
      text += `-------------------\n`;
    }
    text += `BREAKDOWN:\n`;
    const lines = friends.map(f => {
      const cost = itemCosts[f.id] || 0;
      if (cost <= 0) return null;
      const names = items.filter(i => i.sharedWith.includes(f.id)).map(i => i.name).join(', ');
      return `${f.name}: $${cost.toFixed(2)} (${names})`;
    }).filter(Boolean);
    text += lines.join('\n') + `\n\n`;
    if (etransferEmail) text += `💰 e-Transfer to: ${etransferEmail}\n\n`;
    text += `Split via Bill Bot 🤖 https://restaurant-bill-bot.vercel.app/`;
    return text;
  };

  const copyToClipboard = async () => {
    await navigator.clipboard.writeText(generateReportText());
    setCopyFeedback(true);
    setTimeout(() => setCopyFeedback(false), 2000);
  };

  return (
    <div className="min-h-screen bg-slate-100 flex justify-center p-0 md:p-8">
      <div className="w-full max-w-lg bg-white min-h-screen md:min-h-0 md:rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col border border-slate-200 relative">

        {/* Header */}
        <header className="bg-indigo-700 px-8 py-10 text-white relative overflow-hidden">
          <div className="absolute top-10 right-8 bot-float opacity-30"><BotIcon className="w-16 h-16" /></div>
          <div className="relative z-10">
            <h1 className="text-4xl font-black tracking-tight">Bill Bot</h1>
            <p className="text-indigo-200 text-[10px] font-bold uppercase tracking-[0.2em]">Simple restaurant bill splitter</p>
          </div>
        </header>

        {/* Main Content Area */}
        <main className="p-6 flex-1 bg-white flex flex-col overflow-y-auto no-scrollbar">
          <StepProgress currentStep={step} onStepClick={setStep} />

          {/* AI Feedback Bar */}
          <div className="mb-8 flex items-start gap-4 animate-in fade-in slide-in-from-top-2 duration-700">
            <div className="p-2.5 bg-indigo-50 rounded-2xl text-indigo-600 shrink-0">
              <BotIcon className="w-6 h-6" />
            </div>
            <div className="pt-1">
              <p className="text-lg font-bold text-slate-800 leading-tight">
                {getBotSpeech(step)}
              </p>
            </div>
          </div>

          {/* Step Views */}
          <div className="flex-1">
            {step === 1 && (
              <FriendsView 
                friends={friends} 
                setFriends={setFriends} 
                linkingId={linkingFriendId} 
                setLinkingId={setLinkingFriendId} 
              />
            )}

            {step === 2 && (
              <ItemsView 
                items={items} 
                setItems={setItems} 
                friendsCount={friends.length}
              />
            )}

            {step === 3 && (
              <SplitView 
                items={items} 
                friends={friends} 
                setItems={setItems} 
                billConfig={billConfig} 
                setBillConfig={setBillConfig}
                effectiveTip={effectiveTip}
              />
            )}

            {step === 4 && (
              <PaymentsView 
                friends={friends} 
                payments={payments} 
                setPayments={setPayments} 
                grandTotal={grandTotal}
                itemCosts={calculateIndividualCosts(friends, items, effectiveTip - effectiveDiscount)}
              />
            )}

            {step === 5 && (
              <ResultsView 
                settlements={settlements} 
                etransferEmail={etransferEmail} 
                setEtransferEmail={setEtransferEmail}
                onShare={copyToClipboard}
                copyFeedback={copyFeedback}
              />
            )}
          </div>
        </main>

        {/* Footer Navigation */}
        <footer className="p-8 bg-white border-t border-slate-100 flex flex-col gap-4 sticky bottom-0 z-[60]">
          <div className="flex gap-4">
            {step > 1 && (
              <button onClick={handlePrev} className="flex-1 bg-white border-2 border-slate-200 text-slate-400 font-black py-4 rounded-2xl hover:bg-slate-50 transition-all uppercase text-[10px] tracking-widest">
                Back
              </button>
            )}
            <button 
              onClick={step === 5 ? () => window.location.reload() : handleNext} 
              disabled={step === 1 && friends.length < 2} 
              className={`flex-[2] py-4 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-xl transition-all ${ (step === 1 && friends.length < 2) ? 'bg-slate-300 shadow-none grayscale opacity-50 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-[0.98]' }`}
            >
              {step === 5 ? 'New Bill Split 🤖' : 'Next Step'}
            </button>
          </div>
          <div className="text-center pt-2">
            <p className="text-[8px] font-black uppercase text-slate-300 tracking-[0.2em] pointer-events-none whitespace-nowrap">
              - made by wubdubs -
            </p>
          </div>
        </footer>
      </div>
    </div>
  );
};

